INSERT INTO math_step (grade, step_number, step_title, concept, content_json) VALUES
(3, 1, '마트에서 장보기', '받아올림/내림 없는 세 자리 수 덧셈과 뺄셈', '{"subject":"math","step_id":"step_1","step_title":"마트에서 장보기","grade":3,"semester":1,"unit":1,"concept":"받아올림/내림 없는 세 자리 수 덧셈과 뺄셈","cycles":[{"cycle_number":1,"cycle_type":"concept","slides":[{"image":"step1_concept_01.png","text":"마트에서 사과 230원, 우유 150원을 샀어요. 같이 더해볼까요?","confirm_button_text":"확인"},{"image":"step1_concept_02.png","text":"일의 자리 0 + 0 = 0, 십의 자리 3 + 5 = 8, 백의 자리 2 + 1 = 3. 230 + 150 = 380원이에요. 쉽죠?","confirm_button_text":"확인"},{"image":"step1_concept_03.png","text":"이번엔 빼볼게요. 650원을 갖고 있었는데 과자 320원을 샀어요. 650 - 320 = 330원이 남아요!","confirm_button_text":"시작해볼까요?"}]},{"cycle_number":2,"cycle_type":"choice","difficulty":1,"questions":[{"image":"step1_c2_q1.png","text":"마트에서 빵 310원, 주스 240원을 샀어요. 모두 얼마일까요?","options":["450원","550원","650원"],"answer":"550원","hint":[["310 + 240을 같이 해봐요!"],["일의 자리부터요. 0 + 0 = 0, 십의 자리 1 + 4 = ?"],["거의 다 왔어요! 310 + 240 = 5□0"]],"explanation":"잘했어요! 310 + 240 = 550원이에요."},{"image":"step1_c2_q2.png","text":"마트에서 과자 420원, 음료 160원을 샀어요. 모두 얼마일까요?","options":["480원","580원","680원"],"answer":"580원","hint":[["420 + 160을 같이 해봐요!"],["일의 자리부터요. 0 + 0 = 0, 십의 자리 2 + 6 = ?"],["거의 다 왔어요! 420 + 160 = 5□0"]],"explanation":"잘했어요! 420 + 160 = 580원이에요."},{"image":"step1_c2_q3.png","text":"마트에 970원이 있었어요. 빵 650원을 샀어요. 남은 돈은 얼마일까요?","options":["220원","320원","420원"],"answer":"320원","hint":[["970 - 650을 같이 해봐요!"],["일의 자리부터요. 0 - 0 = 0, 십의 자리 7 - 5 = ?"],["거의 다 왔어요! 970 - 650 = 3□0"]],"explanation":"잘했어요! 970 - 650 = 320원이에요."}]},{"cycle_number":3,"cycle_type":"choice","difficulty":2,"questions":[{"image":"step1_c3_q1.png","text":"마트에 875원이 있었어요. 음료수 340원을 샀어요. 남은 돈은 얼마일까요?","options":["435원","535원","635원"],"answer":"535원","hint":[["875 - 340을 같이 해봐요!"],["일의 자리부터요. 5 - 0 = 5, 십의 자리 7 - 4 = ?"],["거의 다 왔어요! 875 - 340 = 5□5"]],"explanation":"잘했어요! 875 - 340 = 535원이에요."},{"image":"step1_c3_q2.png","text":"마트에서 과자 680원, 사탕 250원을 샀어요. 모두 얼마일까요?","options":["830원","930원","940원"],"answer":"930원","hint":[["680 + 250을 같이 해봐요!"],["일의 자리부터요. 0 + 0 = 0, 십의 자리 8 + 5 = ?"],["거의 다 왔어요! 680 + 250 = 9□0"]],"explanation":"잘했어요! 680 + 250 = 930원이에요."},{"image":"step1_c3_q3.png","text":"마트에 875원이 있었어요. 주스 340원을 샀어요. 남은 돈은 얼마일까요?","options":["425원","525원","535원"],"answer":"535원","hint":[["875 - 340을 같이 해봐요!"],["일의 자리부터요. 5 - 0 = 5, 십의 자리 7 - 4 = ?"],["거의 다 왔어요! 875 - 340 = 5□5"]],"explanation":"잘했어요! 875 - 340 = 535원이에요."}]},{"cycle_number":4,"cycle_type":"choice","difficulty":3,"questions":[{"image":"step1_c4_q1.png","text":"마트에서 사과 234원, 바나나 152원을 샀어요. 모두 얼마일까요?","options":["386원","396원","486원"],"answer":"386원","hint":[["234 + 152를 같이 해봐요!"],["일의 자리부터요. 4 + 2 = 6, 십의 자리 3 + 5 = ?"],["거의 다 왔어요! 234 + 152 = 3□6"]],"explanation":"잘했어요! 234 + 152 = 386원이에요."},{"image":"step1_c4_q2.png","text":"마트에 789원이 있었어요. 과자 354원을 샀어요. 남은 돈은 얼마일까요?","options":["325원","425원","435원"],"answer":"435원","hint":[["789 - 354를 같이 해봐요!"],["일의 자리부터요. 9 - 4 = 5, 십의 자리 8 - 5 = ?"],["거의 다 왔어요! 789 - 354 = 4□5"]],"explanation":"잘했어요! 789 - 354 = 435원이에요."},{"image":"step1_c4_q3.png","text":"마트에서 음료 563원, 빵 214원을 샀어요. 모두 얼마일까요?","options":["667원","767원","777원"],"answer":"777원","hint":[["563 + 214를 같이 해봐요!"],["일의 자리부터요. 3 + 4 = 7, 십의 자리 6 + 1 = ?"],["거의 다 왔어요! 563 + 214 = 7□7"]],"explanation":"잘했어요! 563 + 214 = 777원이에요."}]},{"cycle_number":5,"cycle_type":"short_answer","difficulty":4,"questions":[{"image":"step1_c5_q1.png","text":"마트에서 사과 312원, 우유 245원을 샀어요. 모두 얼마일까요?","answer":"557","hint":[["312 + 245를 같이 해봐요!"],["일의 자리부터요. 2 + 5 = 7, 십의 자리 1 + 4 = ?"],["거의 다 왔어요! 312 + 245 = 5□7"]],"explanation":"잘했어요! 312 + 245 = 557원이에요."},{"image":"step1_c5_q2.png","text":"마트에 896원이 있었어요. 과자 453원을 샀어요. 남은 돈은 얼마일까요?","answer":"443","hint":[["896 - 453을 같이 해봐요!"],["일의 자리부터요. 6 - 3 = 3, 십의 자리 9 - 5 = ?"],["거의 다 왔어요! 896 - 453 = 4□3"]],"explanation":"잘했어요! 896 - 453 = 443원이에요."},{"image":"step1_c5_q3.png","text":"마트에서 주스 471원, 빵 326원을 샀어요. 모두 얼마일까요?","answer":"797","hint":[["471 + 326을 같이 해봐요!"],["일의 자리부터요. 1 + 6 = 7, 십의 자리 7 + 2 = ?"],["거의 다 왔어요! 471 + 326 = 7□7"]],"explanation":"잘했어요! 471 + 326 = 797원이에요."}]}]}'::jsonb)
INSERT INTO math_step (grade, step_number, step_title, concept, content_json) VALUES
(3, 2, '용돈 관리하기', '받아올림/내림 1번 있는 세 자리 수 덧셈과 뺄셈', '{"subject":"math","step_id":"step_2","step_title":"용돈 관리하기","grade":3,"semester":1,"unit":1,"concept":"받아올림/내림 1번 있는 세 자리 수 덧셈과 뺄셈","cycles":[{"cycle_number":1,"cycle_type":"concept","slides":[{"image":"step2_concept_01.png","text":"용돈 통장에 246원이 있어요. 오늘 154원을 더 받았어요. 같이 더해볼까요?","confirm_button_text":"확인"},{"image":"step2_concept_02.png","text":"일의 자리 6 + 4 = 10! 10이 되면 앞자리로 1을 올려줘요. 그러면 246 + 154 = 400원이에요. 잘 봤죠?","confirm_button_text":"확인"},{"image":"step2_concept_03.png","text":"이번엔 빼볼게요. 354원 중에서 178원을 썼어요. 뺄 수 없을 땐 앞자리에서 빌려오면 돼요. 354 - 178 = 176원이에요!","confirm_button_text":"시작해볼까요?"}]},{"cycle_number":2,"cycle_type":"choice","difficulty":1,"questions":[{"image":"step2_c2_q1.png","text":"용돈 통장에 135원이 있었어요. 오늘 227원을 더 받았어요. 모두 얼마일까요?","options":["352원","362원","462원"],"answer":"362원","hint":[["135 + 227을 같이 해봐요!"],["일의 자리부터요. 5 + 7 = 12! 10은 앞자리로 올려줘요."],["거의 다 왔어요! 135 + 227 = 3□2"]],"explanation":"잘했어요! 135 + 227 = 362원이에요."},{"image":"step2_c2_q2.png","text":"용돈 통장에 463원이 있었어요. 문구점에서 175원을 썼어요. 남은 돈은 얼마일까요?","options":["278원","288원","388원"],"answer":"288원","hint":[["463 - 175를 같이 해봐요!"],["일의 자리 3 - 5는 뺄 수 없어요. 앞자리에서 10을 빌려와요. 13 - 5 = ?"],["거의 다 왔어요! 463 - 175 = 2□8"]],"explanation":"잘했어요! 463 - 175 = 288원이에요."},{"image":"step2_c2_q3.png","text":"용돈 통장에 254원이 있었어요. 오늘 318원을 더 받았어요. 모두 얼마일까요?","options":["462원","562원","572원"],"answer":"572원","hint":[["254 + 318을 같이 해봐요!"],["일의 자리부터요. 4 + 8 = 12! 10은 앞자리로 올려줘요."],["거의 다 왔어요! 254 + 318 = 5□2"]],"explanation":"잘했어요! 254 + 318 = 572원이에요."}]},{"cycle_number":3,"cycle_type":"choice","difficulty":2,"questions":[{"image":"step2_c3_q1.png","text":"용돈 통장에 347원이 있었어요. 문구점에서 163원을 썼어요. 남은 돈은 얼마일까요?","options":["174원","184원","284원"],"answer":"184원","hint":[["347 - 163을 같이 해봐요!"],["십의 자리 4 - 6은 뺄 수 없어요. 앞자리에서 10을 빌려와요."],["거의 다 왔어요! 347 - 163 = 1□4"]],"explanation":"잘했어요! 347 - 163 = 184원이에요."},{"image":"step2_c3_q2.png","text":"용돈 통장에 276원이 있었어요. 오늘 145원을 더 받았어요. 모두 얼마일까요?","options":["311원","411원","421원"],"answer":"421원","hint":[["276 + 145를 같이 해봐요!"],["일의 자리부터요. 6 + 5 = 11! 10은 앞자리로 올려줘요."],["거의 다 왔어요! 276 + 145 = 4□1"]],"explanation":"잘했어요! 276 + 145 = 421원이에요."},{"image":"step2_c3_q3.png","text":"용돈 통장에 532원이 있었어요. 장난감 가게에서 247원을 썼어요. 남은 돈은 얼마일까요?","options":["275원","285원","385원"],"answer":"285원","hint":[["532 - 247을 같이 해봐요!"],["일의 자리 2 - 7은 뺄 수 없어요. 앞자리에서 10을 빌려와요. 12 - 7 = ?"],["거의 다 왔어요! 532 - 247 = 2□5"]],"explanation":"잘했어요! 532 - 247 = 285원이에요."}]},{"cycle_number":4,"cycle_type":"choice","difficulty":3,"questions":[{"image":"step2_c4_q1.png","text":"용돈 통장에 418원이 있었어요. 선물 사는 데 239원을 썼어요. 남은 돈은 얼마일까요?","options":["169원","179원","279원"],"answer":"179원","hint":[["418 - 239를 같이 해봐요!"],["일의 자리 8 - 9는 뺄 수 없어요. 앞자리에서 10을 빌려와요. 18 - 9 = ?"],["거의 다 왔어요! 418 - 239 = 1□9"]],"explanation":"잘했어요! 418 - 239 = 179원이에요."},{"image":"step2_c4_q2.png","text":"용돈 통장에 364원이 있었어요. 오늘 258원을 더 받았어요. 모두 얼마일까요?","options":["512원","612원","622원"],"answer":"622원","hint":[["364 + 258을 같이 해봐요!"],["일의 자리부터요. 4 + 8 = 12! 10은 앞자리로 올려줘요."],["거의 다 왔어요! 364 + 258 = 6□2"]],"explanation":"잘했어요! 364 + 258 = 622원이에요."},{"image":"step2_c4_q3.png","text":"용돈 통장에 725원이 있었어요. 책 사는 데 346원을 썼어요. 남은 돈은 얼마일까요?","options":["369원","379원","479원"],"answer":"379원","hint":[["725 - 346을 같이 해봐요!"],["일의 자리 5 - 6은 뺄 수 없어요. 앞자리에서 10을 빌려와요. 15 - 6 = ?"],["거의 다 왔어요! 725 - 346 = 3□9"]],"explanation":"잘했어요! 725 - 346 = 379원이에요."}]},{"cycle_number":5,"cycle_type":"short_answer","difficulty":4,"questions":[{"image":"step2_c5_q1.png","text":"용돈 통장에 483원이 있었어요. 문구점에서 256원을 썼어요. 남은 돈은 얼마일까요?","answer":"227","hint":[["483 - 256을 같이 해봐요!"],["일의 자리 3 - 6은 뺄 수 없어요. 앞자리에서 10을 빌려와요. 13 - 6 = ?"],["거의 다 왔어요! 483 - 256 = 2□7"]],"explanation":"잘했어요! 483 - 256 = 227원이에요."},{"image":"step2_c5_q2.png","text":"용돈 통장에 357원이 있었어요. 오늘 174원을 더 받았어요. 모두 얼마일까요?","answer":"531","hint":[["357 + 174를 같이 해봐요!"],["일의 자리부터요. 7 + 4 = 11! 10은 앞자리로 올려줘요."],["거의 다 왔어요! 357 + 174 = 5□1"]],"explanation":"잘했어요! 357 + 174 = 531원이에요."},{"image":"step2_c5_q3.png","text":"용돈 통장에 612원이 있었어요. 장난감 가게에서 358원을 썼어요. 남은 돈은 얼마일까요?","answer":"254","hint":[["612 - 358을 같이 해봐요!"],["일의 자리 2 - 8은 뺄 수 없어요. 앞자리에서 10을 빌려와요. 12 - 8 = ?"],["거의 다 왔어요! 612 - 358 = 2□4"]],"explanation":"잘했어요! 612 - 358 = 254원이에요."}]}]}'::jsonb)
INSERT INTO math_step (grade, step_number, step_title, concept, content_json) VALUES
(3, 3, '생일 파티 준비하기', '받아올림/내림 2번 있는 세 자리 수 덧셈과 뺄셈', '{"subject":"math","step_id":"step_3","step_title":"생일 파티 준비하기","grade":3,"semester":1,"unit":1,"concept":"받아올림/내림 2번 있는 세 자리 수 덧셈과 뺄셈","cycles":[{"cycle_number":1,"cycle_type":"concept","slides":[{"image":"step3_concept_01.png","text":"생일 파티를 준비해요! 케이크 265원, 음료수 178원을 샀어요. 같이 더해볼까요?","confirm_button_text":"확인"},{"image":"step3_concept_02.png","text":"일의 자리 5 + 8 = 13! 10을 앞자리로 올려요. 십의 자리 6 + 7 + 1 = 14! 또 올려요. 백의 자리 2 + 1 + 1 = 4. 265 + 178 = 443원이에요!","confirm_button_text":"확인"},{"image":"step3_concept_03.png","text":"이번엔 빼볼게요. 파티 준비에 524원이 있었는데 장식 사는 데 358원을 썼어요. 뺄 수 없을 때 두 번 빌려오면 돼요. 524 - 358 = 166원이 남아요!","confirm_button_text":"시작해볼까요?"}]},{"cycle_number":2,"cycle_type":"choice","difficulty":1,"questions":[{"image":"step3_c2_q1.png","text":"파티 준비물로 풍선 147원, 케이크 275원을 샀어요. 모두 얼마일까요?","options":["312원","412원","422원"],"answer":"422원","hint":[["147 + 275를 같이 해봐요!"],["일의 자리 7 + 5 = 12! 10을 앞자리로 올려요. 십의 자리 4 + 7 + 1 = 12! 또 올려요."],["거의 다 왔어요! 147 + 275 = 4□2"]],"explanation":"잘했어요! 147 + 275 = 422원이에요."},{"image":"step3_c2_q2.png","text":"파티 준비에 631원이 있었어요. 음료수 사는 데 274원을 썼어요. 남은 돈은 얼마일까요?","options":["347원","357원","457원"],"answer":"357원","hint":[["631 - 274를 같이 해봐요!"],["일의 자리 1 - 4는 뺄 수 없어요. 앞자리에서 10을 빌려와요. 11 - 4 = ?"],["거의 다 왔어요! 631 - 274 = 3□7"]],"explanation":"잘했어요! 631 - 274 = 357원이에요."},{"image":"step3_c2_q3.png","text":"파티 준비물로 초 156원, 장식 278원을 샀어요. 모두 얼마일까요?","options":["324원","424원","434원"],"answer":"434원","hint":[["156 + 278을 같이 해봐요!"],["일의 자리 6 + 8 = 14! 10을 앞자리로 올려요. 십의 자리 5 + 7 + 1 = 13! 또 올려요."],["거의 다 왔어요! 156 + 278 = 4□4"]],"explanation":"잘했어요! 156 + 278 = 434원이에요."}]},{"cycle_number":3,"cycle_type":"choice","difficulty":2,"questions":[{"image":"step3_c3_q1.png","text":"파티 준비에 723원이 있었어요. 케이크 사는 데 456원을 썼어요. 남은 돈은 얼마일까요?","options":["257원","267원","367원"],"answer":"267원","hint":[["723 - 456을 같이 해봐요!"],["일의 자리 3 - 6은 뺄 수 없어요. 앞자리에서 10을 빌려와요. 13 - 6 = ?"],["거의 다 왔어요! 723 - 456 = 2□7"]],"explanation":"잘했어요! 723 - 456 = 267원이에요."},{"image":"step3_c3_q2.png","text":"파티 준비물로 풍선 368원, 리본 274원을 샀어요. 모두 얼마일까요?","options":["532원","632원","642원"],"answer":"642원","hint":[["368 + 274를 같이 해봐요!"],["일의 자리 8 + 4 = 12! 10을 앞자리로 올려요. 십의 자리 6 + 7 + 1 = 14! 또 올려요."],["거의 다 왔어요! 368 + 274 = 6□2"]],"explanation":"잘했어요! 368 + 274 = 642원이에요."},{"image":"step3_c3_q3.png","text":"파티 준비에 815원이 있었어요. 장식 사는 데 367원을 썼어요. 남은 돈은 얼마일까요?","options":["338원","448원","548원"],"answer":"448원","hint":[["815 - 367을 같이 해봐요!"],["일의 자리 5 - 7은 뺄 수 없어요. 앞자리에서 10을 빌려와요. 15 - 7 = ?"],["거의 다 왔어요! 815 - 367 = 4□8"]],"explanation":"잘했어요! 815 - 367 = 448원이에요."}]},{"cycle_number":4,"cycle_type":"choice","difficulty":3,"questions":[{"image":"step3_c4_q1.png","text":"파티 준비물로 초 179원, 케이크 상자 284원을 샀어요. 모두 얼마일까요?","options":["353원","453원","463원"],"answer":"463원","hint":[["179 + 284를 같이 해봐요!"],["일의 자리 9 + 4 = 13! 10을 앞자리로 올려요. 십의 자리 7 + 8 + 1 = 16! 또 올려요."],["거의 다 왔어요! 179 + 284 = 4□3"]],"explanation":"잘했어요! 179 + 284 = 463원이에요."},{"image":"step3_c4_q2.png","text":"파티 준비에 932원이 있었어요. 음식 사는 데 578원을 썼어요. 남은 돈은 얼마일까요?","options":["344원","354원","454원"],"answer":"354원","hint":[["932 - 578을 같이 해봐요!"],["일의 자리 2 - 8은 뺄 수 없어요. 앞자리에서 10을 빌려와요. 12 - 8 = ?"],["거의 다 왔어요! 932 - 578 = 3□4"]],"explanation":"잘했어요! 932 - 578 = 354원이에요."},{"image":"step3_c4_q3.png","text":"파티 준비물로 풍선 467원, 초 295원을 샀어요. 모두 얼마일까요?","options":["652원","752원","762원"],"answer":"762원","hint":[["467 + 295를 같이 해봐요!"],["일의 자리 7 + 5 = 12! 10을 앞자리로 올려요. 십의 자리 6 + 9 + 1 = 16! 또 올려요."],["거의 다 왔어요! 467 + 295 = 7□2"]],"explanation":"잘했어요! 467 + 295 = 762원이에요."}]},{"cycle_number":5,"cycle_type":"short_answer","difficulty":4,"questions":[{"image":"step3_c5_q1.png","text":"파티 준비물로 케이크 358원, 음료수 275원을 샀어요. 모두 얼마일까요?","answer":"633","hint":[["358 + 275를 같이 해봐요!"],["일의 자리 8 + 5 = 13! 10을 앞자리로 올려요. 십의 자리 5 + 7 + 1 = 13! 또 올려요."],["거의 다 왔어요! 358 + 275 = 6□3"]],"explanation":"잘했어요! 358 + 275 = 633원이에요."},{"image":"step3_c5_q2.png","text":"파티 준비에 841원이 있었어요. 장식 사는 데 576원을 썼어요. 남은 돈은 얼마일까요?","answer":"265","hint":[["841 - 576을 같이 해봐요!"],["일의 자리 1 - 6은 뺄 수 없어요. 앞자리에서 10을 빌려와요. 11 - 6 = ?"],["거의 다 왔어요! 841 - 576 = 2□5"]],"explanation":"잘했어요! 841 - 576 = 265원이에요."},{"image":"step3_c5_q3.png","text":"파티 준비물로 풍선 486원, 리본 357원을 샀어요. 모두 얼마일까요?","answer":"843","hint":[["486 + 357을 같이 해봐요!"],["일의 자리 6 + 7 = 13! 10을 앞자리로 올려요. 십의 자리 8 + 5 + 1 = 14! 또 올려요."],["거의 다 왔어요! 486 + 357 = 8□3"]],"explanation":"잘했어요! 486 + 357 = 843원이에요."}]}]}'::jsonb)
INSERT INTO math_step (grade, step_number, step_title, concept, content_json) VALUES
(4, 1, '저금통 열기', '만, 다섯 자리 수 읽기와 쓰기', '{"subject":"math","step_id":"step_1","step_title":"저금통 열기","grade":4,"semester":1,"unit":1,"concept":"만, 다섯 자리 수 읽기와 쓰기","cycles":[{"cycle_number":1,"cycle_type":"concept","slides":[{"image":"g4_step1_concept_01.png","text":"저금통을 열었더니 만원짜리 6장, 천원짜리 2장, 백원짜리 5개, 십원짜리 3개, 일원짜리 7개가 있어요. 모두 얼마일까요?","confirm_button_text":"확인"},{"image":"g4_step1_concept_02.png","text":"만원짜리 6장 → 60000원, 천원짜리 2장 → 2000원, 백원짜리 5개 → 500원, 십원짜리 3개 → 30원, 일원짜리 7개 → 7원. 모두 더하면 62537원이에요!","confirm_button_text":"확인"},{"image":"g4_step1_concept_03.png","text":"62537은 ''육만 이천오백삼십칠''이라고 읽어요. 만의 자리부터 차례로 읽으면 돼요!","confirm_button_text":"시작해볼까요?"}]},{"cycle_number":2,"cycle_type":"choice","difficulty":1,"questions":[{"image":"g4_step1_c2_q1.png","text":"저금통에 만원짜리 3장, 천원짜리 4장, 백원짜리 2개, 십원짜리 1개, 일원짜리 5개가 있어요. 모두 얼마일까요?","options":["34215원","34125원","43215원"],"answer":"34215원","hint":[["34215원을 같이 찾아봐요!"],["만원짜리 3장은 30000원, 천원짜리 4장은 4000원이에요. 30000 + 4000 = ?"],["거의 다 왔어요! 30000 + 4000 + 200 + 10 + 5 = 3□215"]],"explanation":"잘했어요! 만원짜리 3장, 천원짜리 4장, 백원짜리 2개, 십원짜리 1개, 일원짜리 5개는 34215원이에요."},{"image":"g4_step1_c2_q2.png","text":"저금통에 51304원이 있어요. 이 수를 바르게 읽은 것은 무엇일까요?","options":["오만 천삼백사","오만 일천삼백사","오만 천삼백영사"],"answer":"오만 천삼백사","hint":[["51304를 같이 읽어봐요!"],["50000은 ''오만'', 1000은 ''천'', 300은 ''삼백''이에요."],["거의 다 왔어요! 오만 + 천 + 삼백 + □ = 오만 천삼백□"]],"explanation":"잘했어요! 51304는 ''오만 천삼백사''라고 읽어요."},{"image":"g4_step1_c2_q3.png","text":"''이만 삼천육백오십팔''을 숫자로 쓰면 얼마일까요?","options":["23658원","32658원","23568원"],"answer":"23658원","hint":[["이만 삼천육백오십팔을 같이 써봐요!"],["이만 = 20000, 삼천 = 3000, 육백 = 600이에요."],["거의 다 왔어요! 20000 + 3000 + 600 + 50 + 8 = 2□658"]],"explanation":"잘했어요! 이만 삼천육백오십팔은 23658원이에요."}]},{"cycle_number":3,"cycle_type":"choice","difficulty":2,"questions":[{"image":"g4_step1_c3_q1.png","text":"저금통에 만원짜리 5장, 천원짜리 0장, 백원짜리 7개, 십원짜리 4개, 일원짜리 2개가 있어요. 모두 얼마일까요?","options":["50742원","57042원","50472원"],"answer":"50742원","hint":[["50742원을 같이 찾아봐요!"],["만원짜리 5장은 50000원이에요. 천원짜리가 0장이면 천의 자리는 0이에요."],["거의 다 왔어요! 50000 + 0 + 700 + 40 + 2 = 5□742"]],"explanation":"잘했어요! 50742원이에요. 천의 자리가 0일 때는 읽지 않아요!"},{"image":"g4_step1_c3_q2.png","text":"다음 중 가장 큰 수는 무엇일까요?","options":["47820원","74820원","47280원"],"answer":"74820원","hint":[["가장 큰 수를 찾으려면 만의 자리부터 비교해봐요!"],["47820의 만의 자리는 4, 74820의 만의 자리는 7이에요. 어느 게 더 클까요?"],["거의 다 왔어요! 만의 자리가 □인 수가 가장 커요."]],"explanation":"잘했어요! 만의 자리 숫자가 가장 큰 74820이 제일 커요."},{"image":"g4_step1_c3_q3.png","text":"저금통에 만원짜리 8장, 천원짜리 3장이 있어요. 백원, 십원, 일원은 없어요. 모두 얼마일까요?","options":["83000원","80300원","38000원"],"answer":"83000원","hint":[["83000원을 같이 찾아봐요!"],["만원짜리 8장은 80000원, 천원짜리 3장은 3000원이에요."],["거의 다 왔어요! 80000 + 3000 = 8□000"]],"explanation":"잘했어요! 80000 + 3000 = 83000원이에요."}]},{"cycle_number":4,"cycle_type":"choice","difficulty":3,"questions":[{"image":"g4_step1_c4_q1.png","text":"저금통에 만원짜리 4장, 천원짜리 9장, 백원짜리 3개가 있어요. 이 돈은 얼마일까요?","options":["49300원","49030원","40930원"],"answer":"49300원","hint":[["49300원을 같이 찾아봐요!"],["만원짜리 4장은 40000원, 천원짜리 9장은 9000원이에요."],["거의 다 왔어요! 40000 + 9000 + 300 = 4□300"]],"explanation":"잘했어요! 40000 + 9000 + 300 = 49300원이에요."},{"image":"g4_step1_c4_q2.png","text":"63052에서 6이 나타내는 값은 얼마일까요?","options":["6원","600원","60000원"],"answer":"60000원","hint":[["63052에서 6이 어느 자리에 있는지 봐봐요!"],["63052는 만의 자리가 6이에요. 만의 자리 6은 얼마를 나타낼까요?"],["거의 다 왔어요! 만의 자리 6은 6 × 10000 = □0000"]],"explanation":"잘했어요! 63052에서 6은 만의 자리에 있어서 60000을 나타내요."},{"image":"g4_step1_c4_q3.png","text":"70000원을 1000원짜리 지폐로 바꾸면 몇 장일까요?","options":["7장","70장","700장"],"answer":"70장","hint":[["70000원을 1000원으로 나눠봐요!"],["10000원은 1000원짜리 10장이에요. 그러면 70000원은 몇 장일까요?"],["거의 다 왔어요! 10000원 → 10장이면, 70000원 → □0장"]],"explanation":"잘했어요! 70000 ÷ 1000 = 70장이에요."}]},{"cycle_number":5,"cycle_type":"short_answer","difficulty":4,"questions":[{"image":"g4_step1_c5_q1.png","text":"저금통에 만원짜리 5장, 천원짜리 6장, 백원짜리 4개, 십원짜리 8개, 일원짜리 3개가 있어요. 모두 얼마인지 숫자로 써봐요!","answer":"56483","hint":[["각 자리 숫자를 더해봐요!"],["50000 + 6000 + 400 + 80 + 3을 계산해봐요."],["거의 다 왔어요! 50000 + 6000 + 400 + 80 + 3 = 5□483"]],"explanation":"잘했어요! 50000 + 6000 + 400 + 80 + 3 = 56483원이에요."},{"image":"g4_step1_c5_q2.png","text":"80000원을 1000원짜리 지폐로 바꾸면 몇 장일까요?","answer":"80","hint":[["80000원을 1000원으로 나눠봐요!"],["10000원은 1000원짜리 10장이에요. 80000원은 10000원이 몇 개일까요?"],["거의 다 왔어요! 80000 ÷ 1000 = □0장"]],"explanation":"잘했어요! 80000 ÷ 1000 = 80장이에요."},{"image":"g4_step1_c5_q3.png","text":"만의 자리 숫자가 7, 천의 자리 숫자가 3, 백의 자리 숫자가 0, 십의 자리 숫자가 5, 일의 자리 숫자가 9인 다섯 자리 수는 얼마일까요?","answer":"73059","hint":[["자리별로 숫자를 놓아봐요!"],["만의 자리 7 → 70000, 천의 자리 3 → 3000, 백의 자리 0 → 0이에요."],["거의 다 왔어요! 70000 + 3000 + 0 + 50 + 9 = 7□059"]],"explanation":"잘했어요! 70000 + 3000 + 0 + 50 + 9 = 73059이에요."}]}]}'::jsonb)
INSERT INTO math_step (grade, step_number, step_title, concept, content_json) VALUES
(4, 2, '저금통 돈 불리기', '뛰어세기', '{"subject":"math","step_id":"step_2","step_title":"저금통 돈 불리기","grade":4,"semester":1,"unit":1,"concept":"뛰어세기","cycles":[{"cycle_number":1,"cycle_type":"concept","slides":[{"image":"g4_step2_concept_01.png","text":"저금통에 10000원이 있어요. 매주 10000원씩 더 넣으면 얼마가 될까요? 같이 세어봐요!","confirm_button_text":"확인"},{"image":"g4_step2_concept_02.png","text":"10000 → 20000 → 30000 → 40000! 10000씩 뛰어세면 만의 자리 숫자가 1씩 커져요. 쉽죠?","confirm_button_text":"확인"},{"image":"g4_step2_concept_03.png","text":"1000씩 뛰어세면 어떨까요? 23000 → 24000 → 25000 → 26000! 천의 자리 숫자가 1씩 커져요!","confirm_button_text":"시작해볼까요?"}]},{"cycle_number":2,"cycle_type":"choice","difficulty":1,"questions":[{"image":"g4_step2_c2_q1.png","text":"저금통에 10000원씩 넣고 있어요. 20000 → 30000 → 40000 → 다음은 얼마일까요?","options":["41000원","50000원","45000원"],"answer":"50000원","hint":[["10000씩 뛰어세고 있어요!"],["40000에서 10000을 더하면 얼마일까요?"],["거의 다 왔어요! 40000 + 10000 = □0000"]],"explanation":"잘했어요! 10000씩 뛰어세면 40000 다음은 50000이에요."},{"image":"g4_step2_c2_q2.png","text":"저금통에 1000원씩 넣고 있어요. 31000 → 32000 → 33000 → 다음은 얼마일까요?","options":["34000원","43000원","33100원"],"answer":"34000원","hint":[["1000씩 뛰어세고 있어요!"],["33000에서 1000을 더하면 얼마일까요?"],["거의 다 왔어요! 33000 + 1000 = □4000"]],"explanation":"잘했어요! 1000씩 뛰어세면 33000 다음은 34000이에요."},{"image":"g4_step2_c2_q3.png","text":"저금통에 10000원씩 넣고 있어요. 45000 → 55000 → 65000 → 다음은 얼마일까요?","options":["66000원","75000원","70000원"],"answer":"75000원","hint":[["10000씩 뛰어세고 있어요!"],["65000에서 10000을 더하면 얼마일까요?"],["거의 다 왔어요! 65000 + 10000 = □5000"]],"explanation":"잘했어요! 10000씩 뛰어세면 65000 다음은 75000이에요."}]},{"cycle_number":3,"cycle_type":"choice","difficulty":2,"questions":[{"image":"g4_step2_c3_q1.png","text":"□ 안에 들어갈 수는 얼마일까요? 52000 → 54000 → 56000 → □","options":["57000원","58000원","60000원"],"answer":"58000원","hint":[["얼마씩 뛰어세고 있는지 먼저 찾아봐요!"],["52000에서 54000이 되려면 2000이 늘었어요. 2000씩 뛰어세고 있어요!"],["거의 다 왔어요! 56000 + 2000 = □8000"]],"explanation":"잘했어요! 2000씩 뛰어세면 56000 다음은 58000이에요."},{"image":"g4_step2_c3_q2.png","text":"□ 안에 들어갈 수는 얼마일까요? 73000 → □ → 93000 → 103000","options":["80000원","83000원","85000원"],"answer":"83000원","hint":[["얼마씩 뛰어세고 있는지 먼저 찾아봐요!"],["93000에서 103000이 되려면 10000이 늘었어요. 10000씩 뛰어세고 있어요!"],["거의 다 왔어요! 73000 + 10000 = □3000"]],"explanation":"잘했어요! 10000씩 뛰어세면 73000 다음은 83000이에요."},{"image":"g4_step2_c3_q3.png","text":"저금통에 매달 5000원씩 넣어요. 15000원에서 시작하면 3달 후에는 얼마일까요?","options":["25000원","30000원","35000원"],"answer":"30000원","hint":[["5000씩 3번 뛰어세봐요!"],["15000 → 20000 → 25000 → ?"],["거의 다 왔어요! 25000 + 5000 = □0000"]],"explanation":"잘했어요! 15000 → 20000 → 25000 → 30000이에요."}]},{"cycle_number":4,"cycle_type":"choice","difficulty":3,"questions":[{"image":"g4_step2_c4_q1.png","text":"□ 안에 들어갈 수는 얼마일까요? 28000 → □ → □ → 58000","options":["38000원, 48000원","36000원, 46000원","30000원, 40000원"],"answer":"38000원, 48000원","hint":[["58000 - 28000 = 30000이에요. 3번 뛰어야 하니까 얼마씩 뛰는 걸까요?"],["30000 ÷ 3 = 10000! 10000씩 뛰어세고 있어요."],["거의 다 왔어요! 28000 + 10000 = □8000, □8000 + 10000 = □8000"]],"explanation":"잘했어요! 10000씩 뛰어세면 28000 → 38000 → 48000 → 58000이에요."},{"image":"g4_step2_c4_q2.png","text":"저금통에 매주 3000원씩 넣어요. 지금 24000원이 있어요. 4주 후에는 얼마일까요?","options":["34000원","36000원","38000원"],"answer":"36000원","hint":[["3000씩 4번 뛰어세봐요!"],["24000 → 27000 → 30000 → 33000 → ?"],["거의 다 왔어요! 33000 + 3000 = □6000"]],"explanation":"잘했어요! 24000 → 27000 → 30000 → 33000 → 36000이에요."},{"image":"g4_step2_c4_q3.png","text":"□ 안에 들어갈 수는 얼마일까요? 61000 → 63000 → 65000 → □ → 69000","options":["66000원","67000원","68000원"],"answer":"67000원","hint":[["얼마씩 뛰어세고 있는지 먼저 찾아봐요!"],["61000에서 63000이 되려면 2000이 늘었어요. 2000씩 뛰어세고 있어요!"],["거의 다 왔어요! 65000 + 2000 = □7000"]],"explanation":"잘했어요! 2000씩 뛰어세면 65000 다음은 67000이에요."}]},{"cycle_number":5,"cycle_type":"short_answer","difficulty":4,"questions":[{"image":"g4_step2_c5_q1.png","text":"저금통에 매주 10000원씩 넣어요. 지금 32000원이 있어요. 5주 후에는 얼마일까요?","answer":"82000","hint":[["10000씩 5번 뛰어세봐요!"],["32000 → 42000 → 52000 → 62000 → 72000 → ?"],["거의 다 왔어요! 72000 + 10000 = □2000"]],"explanation":"잘했어요! 32000 → 42000 → 52000 → 62000 → 72000 → 82000이에요."},{"image":"g4_step2_c5_q2.png","text":"□ 안에 들어갈 수를 써봐요. 45000 → 50000 → 55000 → □","answer":"60000","hint":[["얼마씩 뛰어세고 있는지 먼저 찾아봐요!"],["45000에서 50000이 되려면 5000이 늘었어요. 5000씩 뛰어세고 있어요!"],["거의 다 왔어요! 55000 + 5000 = □0000"]],"explanation":"잘했어요! 5000씩 뛰어세면 55000 다음은 60000이에요."},{"image":"g4_step2_c5_q3.png","text":"저금통에 매달 4000원씩 넣어요. 지금 21000원이 있어요. 3달 후에는 얼마일까요?","answer":"33000","hint":[["4000씩 3번 뛰어세봐요!"],["21000 → 25000 → 29000 → ?"],["거의 다 왔어요! 29000 + 4000 = □3000"]],"explanation":"잘했어요! 21000 → 25000 → 29000 → 33000이에요."}]}]}'::jsonb)
INSERT INTO math_step (grade, step_number, step_title, concept, content_json) VALUES
(4, 3, '누가 더 많이 모았을까?', '수의 크기 비교', '{"subject":"math","step_id":"step_3","step_title":"누가 더 많이 모았을까?","grade":4,"semester":1,"unit":1,"concept":"수의 크기 비교","cycles":[{"cycle_number":1,"cycle_type":"concept","slides":[{"image":"g4_step3_concept_01.png","text":"친구 둘이 저금통을 열었어요. 민준이는 47500원, 지아는 52300원이 있어요. 누가 더 많이 모았을까요?","confirm_button_text":"확인"},{"image":"g4_step3_concept_02.png","text":"자릿수가 같으면 가장 높은 자리부터 비교해요! 만의 자리를 보면 민준이는 4, 지아는 5예요. 5가 더 크니까 지아가 더 많이 모았어요!","confirm_button_text":"확인"},{"image":"g4_step3_concept_03.png","text":"만약 만의 자리가 같으면 천의 자리를 비교해요. 높은 자리 숫자가 클수록 더 큰 수예요. 차례대로 비교하면 돼요!","confirm_button_text":"시작해볼까요?"}]},{"cycle_number":2,"cycle_type":"choice","difficulty":1,"questions":[{"image":"g4_step3_c2_q1.png","text":"민준이는 35000원, 지아는 53000원을 모았어요. 누가 더 많이 모았을까요?","options":["민준이","지아","똑같아요"],"answer":"지아","hint":[["만의 자리부터 비교해봐요!"],["35000의 만의 자리는 3, 53000의 만의 자리는 5예요. 어느 게 더 클까요?"],["거의 다 왔어요! 만의 자리 □가 더 크니까 □가 더 많이 모았어요."]],"explanation":"잘했어요! 만의 자리를 보면 5 > 3이니까 53000원인 지아가 더 많이 모았어요."},{"image":"g4_step3_c2_q2.png","text":"다음 중 가장 큰 수는 무엇일까요?","options":["62400원","26400원","64200원"],"answer":"64200원","hint":[["만의 자리부터 비교해봐요!"],["62400의 만의 자리는 6, 26400의 만의 자리는 2, 64200의 만의 자리는 6이에요."],["거의 다 왔어요! 만의 자리가 같은 62400과 64200은 천의 자리를 비교해요. 2와 4 중 □가 더 커요."]],"explanation":"잘했어요! 만의 자리가 같은 62400과 64200은 천의 자리를 비교해요. 4 > 2니까 64200이 가장 커요."},{"image":"g4_step3_c2_q3.png","text":"□ 안에 들어갈 알맞은 기호는 무엇일까요? 45230 □ 45320","options":[">","<","="],"answer":"<","hint":[["높은 자리부터 차례로 비교해봐요!"],["만의 자리 4 = 4, 천의 자리 5 = 5, 백의 자리를 비교해봐요. 2와 3 중 어느 게 더 클까요?"],["거의 다 왔어요! 백의 자리가 2 □ 3이니까 45230 □ 45320이에요."]],"explanation":"잘했어요! 백의 자리를 보면 2 < 3이니까 45230 < 45320이에요."}]},{"cycle_number":3,"cycle_type":"choice","difficulty":2,"questions":[{"image":"g4_step3_c3_q1.png","text":"세 친구가 저금통을 열었어요. 민준 38500원, 지아 38050원, 수아 39500원. 가장 많이 모은 친구는 누구일까요?","options":["민준","지아","수아"],"answer":"수아","hint":[["만의 자리부터 비교해봐요!"],["세 수 모두 만의 자리가 3으로 같아요. 천의 자리를 비교해봐요. 8, 8, 9 중 어느 게 가장 클까요?"],["거의 다 왔어요! 천의 자리가 □인 수아가 가장 많이 모았어요."]],"explanation":"잘했어요! 천의 자리를 보면 9 > 8이니까 39500원인 수아가 가장 많이 모았어요."},{"image":"g4_step3_c3_q2.png","text":"다음 중 가장 작은 수는 무엇일까요?","options":["71350원","71530원","71305원"],"answer":"71305원","hint":[["높은 자리부터 차례로 비교해봐요!"],["만의 자리 7 = 7, 천의 자리 1 = 1, 백의 자리를 비교해봐요. 3, 5, 3 중 5가 가장 크니까 71530은 아니에요."],["거의 다 왔어요! 71350과 71305의 십의 자리를 비교해봐요. 5와 0 중 □가 더 작아요."]],"explanation":"잘했어요! 71350과 71305의 십의 자리를 보면 0 < 5니까 71305가 가장 작아요."},{"image":"g4_step3_c3_q3.png","text":"□ 안에 들어갈 수 있는 숫자는 무엇일까요? 6□400 > 65400","options":["4","5","6"],"answer":"6","hint":[["천의 자리 숫자를 비교해봐요!"],["6□400 > 65400이 되려면 □가 5보다 커야 해요."],["거의 다 왔어요! 5보다 큰 한 자리 숫자는 □, 7, 8, 9예요."]],"explanation":"잘했어요! □가 5보다 커야 하니까 6, 7, 8, 9가 들어갈 수 있어요. 보기 중에는 6이에요."}]},{"cycle_number":4,"cycle_type":"choice","difficulty":3,"questions":[{"image":"g4_step3_c4_q1.png","text":"숫자 카드 3, 7, 1, 9, 5를 한 번씩 사용해서 가장 큰 다섯 자리 수를 만들면 얼마일까요?","options":["97531","97513","95731"],"answer":"97531","hint":[["가장 큰 수를 만들려면 큰 숫자를 높은 자리에 놓아야 해요!"],["가장 큰 숫자 9를 만의 자리에, 그 다음 큰 숫자 7을 천의 자리에 놓아봐요."],["거의 다 왔어요! 9, 7, □, □, □ 순서로 남은 숫자 중 큰 것부터 놓아요."]],"explanation":"잘했어요! 큰 숫자부터 높은 자리에 놓으면 97531이에요."},{"image":"g4_step3_c4_q2.png","text":"숫자 카드 2, 8, 4, 6, 0을 한 번씩 사용해서 가장 작은 다섯 자리 수를 만들면 얼마일까요?","options":["20468","20486","02468"],"answer":"20468","hint":[["가장 작은 수를 만들려면 작은 숫자를 높은 자리에 놓아야 해요!"],["0은 만의 자리에 올 수 없어요. 그러면 가장 작은 숫자는 2예요. 2를 만의 자리에 놓아봐요."],["거의 다 왔어요! 2, 0, □, □, □ 순서로 남은 숫자 중 작은 것부터 놓아요."]],"explanation":"잘했어요! 0은 맨 앞에 올 수 없으니까 2를 만의 자리에 놓고, 나머지를 작은 순서로 놓으면 20468이에요."},{"image":"g4_step3_c4_q3.png","text":"□ 안에 들어갈 수 있는 숫자를 모두 고르면? 8□250 < 83250","options":["0, 1, 2","4, 5, 6","3, 4, 5"],"answer":"0, 1, 2","hint":[["천의 자리 숫자를 비교해봐요!"],["8□250 < 83250이 되려면 □가 3보다 작아야 해요."],["거의 다 왔어요! 3보다 작은 한 자리 숫자는 0, 1, □예요."]],"explanation":"잘했어요! □가 3보다 작아야 하니까 0, 1, 2가 들어갈 수 있어요."}]},{"cycle_number":5,"cycle_type":"short_answer","difficulty":4,"questions":[{"image":"g4_step3_c5_q1.png","text":"숫자 카드 5, 1, 8, 3, 6을 한 번씩 사용해서 가장 큰 다섯 자리 수를 만들면 얼마일까요?","answer":"86531","hint":[["가장 큰 숫자부터 높은 자리에 놓아봐요!"],["가장 큰 숫자 8을 만의 자리에, 그 다음 큰 숫자 6을 천의 자리에 놓아봐요."],["거의 다 왔어요! 8, 6, □, □, □ 순서로 남은 숫자 중 큰 것부터 놓아요."]],"explanation":"잘했어요! 큰 숫자부터 높은 자리에 놓으면 86531이에요."},{"image":"g4_step3_c5_q2.png","text":"세 친구의 저금통이에요. 민준 74320원, 지아 74230원, 수아 74302원. 가장 많이 모은 친구의 금액을 써봐요!","answer":"74320","hint":[["높은 자리부터 차례로 비교해봐요!"],["만의 자리 7 = 7, 천의 자리 4 = 4, 백의 자리를 비교해봐요. 3 = 3 = 3, 십의 자리를 비교해봐요."],["거의 다 왔어요! 십의 자리가 2, 3, 0 중 □가 가장 커요."]],"explanation":"잘했어요! 십의 자리를 보면 3 > 2 > 0이니까 74320원인 민준이가 가장 많이 모았어요."},{"image":"g4_step3_c5_q3.png","text":"숫자 카드 4, 0, 7, 2, 9를 한 번씩 사용해서 가장 작은 다섯 자리 수를 만들면 얼마일까요?","answer":"20479","hint":[["가장 작은 숫자부터 높은 자리에 놓아봐요!"],["0은 만의 자리에 올 수 없어요. 가장 작은 숫자 2를 만의 자리에 놓아봐요."],["거의 다 왔어요! 2, 0, □, □, □ 순서로 남은 숫자 중 작은 것부터 놓아요."]],"explanation":"잘했어요! 0은 맨 앞에 올 수 없으니까 2를 만의 자리에 놓고, 나머지를 작은 순서로 놓으면 20479예요."}]}]}'::jsonb)
INSERT INTO math_step (grade, step_number, step_title, concept, content_json) VALUES
(5, 1, '용돈 기입장 쓰기', '덧셈과 뺄셈이 섞여있는 식', '{"subject":"math","step_id":"step_1","step_title":"용돈 기입장 쓰기","grade":5,"semester":1,"unit":1,"concept":"덧셈과 뺄셈이 섞여있는 식","cycles":[{"cycle_number":1,"cycle_type":"concept","slides":[{"image":"g5_step1_concept_01.png","text":"오늘 용돈 기입장을 써볼게요. 처음에 2000원이 있었어요. 엄마한테 3000원을 받고, 과자를 1500원어치 샀어요. 남은 돈은 얼마일까요?","confirm_button_text":"확인"},{"image":"g5_step1_concept_02.png","text":"덧셈과 뺄셈이 섞여있으면 앞에서부터 차례로 계산해요! 2000 + 3000 = 5000, 5000 - 1500 = 3500. 남은 돈은 3500원이에요!","confirm_button_text":"확인"},{"image":"g5_step1_concept_03.png","text":"덧셈 뺄셈이 섞여있을 땐 순서대로 하나씩 계산하면 돼요. 어렵지 않죠? 같이 해봐요!","confirm_button_text":"시작해볼까요?"}]},{"cycle_number":2,"cycle_type":"choice","difficulty":1,"questions":[{"image":"g5_step1_c2_q1.png","text":"처음에 3000원이 있었어요. 아빠한테 2000원을 받았어요. 음료수를 1000원에 샀어요. 남은 돈은 얼마일까요?","options":["3000원","4000원","5000원"],"answer":"4000원","hint":[["앞에서부터 차례로 계산해봐요!"],["3000 + 2000 = 5000, 5000 - 1000 = ?"],["거의 다 왔어요! 5000 - 1000 = □000"]],"explanation":"잘했어요! 3000 + 2000 - 1000 = 4000원이에요."},{"image":"g5_step1_c2_q2.png","text":"처음에 5000원이 있었어요. 빵을 2000원에 샀어요. 할머니한테 3000원을 받았어요. 지금 돈은 얼마일까요?","options":["5000원","6000원","7000원"],"answer":"6000원","hint":[["앞에서부터 차례로 계산해봐요!"],["5000 - 2000 = 3000, 3000 + 3000 = ?"],["거의 다 왔어요! 3000 + 3000 = □000"]],"explanation":"잘했어요! 5000 - 2000 + 3000 = 6000원이에요."},{"image":"g5_step1_c2_q3.png","text":"처음에 4000원이 있었어요. 문구점에서 1500원을 썼어요. 엄마한테 2500원을 받았어요. 지금 돈은 얼마일까요?","options":["4000원","5000원","6000원"],"answer":"5000원","hint":[["앞에서부터 차례로 계산해봐요!"],["4000 - 1500 = 2500, 2500 + 2500 = ?"],["거의 다 왔어요! 2500 + 2500 = □000"]],"explanation":"잘했어요! 4000 - 1500 + 2500 = 5000원이에요."}]},{"cycle_number":3,"cycle_type":"choice","difficulty":2,"questions":[{"image":"g5_step1_c3_q1.png","text":"처음에 6000원이 있었어요. 과자를 2500원에 사고, 친구한테 1000원을 빌려줬어요. 지금 돈은 얼마일까요?","options":["2500원","3500원","4500원"],"answer":"2500원","hint":[["앞에서부터 차례로 계산해봐요!"],["6000 - 2500 = 3500, 3500 - 1000 = ?"],["거의 다 왔어요! 3500 - 1000 = □500"]],"explanation":"잘했어요! 6000 - 2500 - 1000 = 2500원이에요."},{"image":"g5_step1_c3_q2.png","text":"처음에 1000원이 있었어요. 용돈 5000원을 받았어요. 책을 3500원에 샀어요. 지금 돈은 얼마일까요?","options":["1500원","2500원","3500원"],"answer":"2500원","hint":[["앞에서부터 차례로 계산해봐요!"],["1000 + 5000 = 6000, 6000 - 3500 = ?"],["거의 다 왔어요! 6000 - 3500 = □500"]],"explanation":"잘했어요! 1000 + 5000 - 3500 = 2500원이에요."},{"image":"g5_step1_c3_q3.png","text":"처음에 8000원이 있었어요. 음료수를 1500원에 사고, 친구한테 2000원을 받았어요. 지금 돈은 얼마일까요?","options":["7500원","8500원","9500원"],"answer":"8500원","hint":[["앞에서부터 차례로 계산해봐요!"],["8000 - 1500 = 6500, 6500 + 2000 = ?"],["거의 다 왔어요! 6500 + 2000 = □500"]],"explanation":"잘했어요! 8000 - 1500 + 2000 = 8500원이에요."}]},{"cycle_number":4,"cycle_type":"choice","difficulty":3,"questions":[{"image":"g5_step1_c4_q1.png","text":"처음에 5000원이 있었어요. 과자 1200원을 사고, 엄마한테 3000원을 받고, 음료수 1800원을 샀어요. 지금 돈은 얼마일까요?","options":["4000원","5000원","6000원"],"answer":"5000원","hint":[["앞에서부터 차례로 계산해봐요!"],["5000 - 1200 = 3800, 3800 + 3000 = 6800, 6800 - 1800 = ?"],["거의 다 왔어요! 6800 - 1800 = □000"]],"explanation":"잘했어요! 5000 - 1200 + 3000 - 1800 = 5000원이에요."},{"image":"g5_step1_c4_q2.png","text":"처음에 2000원이 있었어요. 할머니한테 4000원을 받고, 문구점에서 2500원을 쓰고, 친구한테 500원을 받았어요. 지금 돈은 얼마일까요?","options":["2000원","3000원","4000원"],"answer":"3000원","hint":[["앞에서부터 차례로 계산해봐요!"],["2000 + 4000 = 6000, 6000 - 2500 = 3500, 3500 + 500 = ?"],["거의 다 왔어요! 3500 + 500 = □000"]],"explanation":"잘했어요! 2000 + 4000 - 2500 + 500 = 4000원이에요."},{"image":"g5_step1_c4_q3.png","text":"처음에 7000원이 있었어요. 빵 2500원을 사고, 용돈 3000원을 받고, 음료수 1500원을 샀어요. 지금 돈은 얼마일까요?","options":["5000원","6000원","7000원"],"answer":"6000원","hint":[["앞에서부터 차례로 계산해봐요!"],["7000 - 2500 = 4500, 4500 + 3000 = 7500, 7500 - 1500 = ?"],["거의 다 왔어요! 7500 - 1500 = □000"]],"explanation":"잘했어요! 7000 - 2500 + 3000 - 1500 = 6000원이에요."}]},{"cycle_number":5,"cycle_type":"short_answer","difficulty":4,"questions":[{"image":"g5_step1_c5_q1.png","text":"처음에 3000원이 있었어요. 엄마한테 4000원을 받고, 과자 2500원을 샀어요. 지금 돈은 얼마일까요?","answer":"4500","hint":[["앞에서부터 차례로 계산해봐요!"],["3000 + 4000 = 7000, 7000 - 2500 = ?"],["거의 다 왔어요! 7000 - 2500 = □500"]],"explanation":"잘했어요! 3000 + 4000 - 2500 = 4500원이에요."},{"image":"g5_step1_c5_q2.png","text":"처음에 6000원이 있었어요. 문구점에서 1500원을 쓰고, 아빠한테 2000원을 받고, 음료수 500원을 샀어요. 지금 돈은 얼마일까요?","answer":"6000","hint":[["앞에서부터 차례로 계산해봐요!"],["6000 - 1500 = 4500, 4500 + 2000 = 6500, 6500 - 500 = ?"],["거의 다 왔어요! 6500 - 500 = □000"]],"explanation":"잘했어요! 6000 - 1500 + 2000 - 500 = 6000원이에요."},{"image":"g5_step1_c5_q3.png","text":"처음에 5000원이 있었어요. 빵 1000원을 사고, 할머니한테 3000원을 받고, 과자 2000원을 샀어요. 지금 돈은 얼마일까요?","answer":"5000","hint":[["앞에서부터 차례로 계산해봐요!"],["5000 - 1000 = 4000, 4000 + 3000 = 7000, 7000 - 2000 = ?"],["거의 다 왔어요! 7000 - 2000 = □000"]],"explanation":"잘했어요! 5000 - 1000 + 3000 - 2000 = 5000원이에요."}]}]}'::jsonb)
INSERT INTO math_step (grade, step_number, step_title, concept, content_json) VALUES
(5, 2, '급식 도우미', '곱셈과 나눗셈이 섞여있는 식', '{"subject":"math","step_id":"step_2","step_title":"급식 도우미","grade":5,"semester":1,"unit":1,"concept":"곱셈과 나눗셈이 섞여있는 식","cycles":[{"cycle_number":1,"cycle_type":"concept","slides":[{"image":"g5_step2_concept_01.png","text":"급식 도우미가 되었어요! 과자 24개를 6명이 똑같이 나눠 가졌어요. 한 명이 가진 과자를 2배로 늘리면 몇 개일까요?","confirm_button_text":"확인"},{"image":"g5_step2_concept_02.png","text":"곱셈과 나눗셈이 섞여있으면 앞에서부터 차례로 계산해요! 24 ÷ 6 = 4, 4 × 2 = 8. 한 명이 8개를 갖게 돼요!","confirm_button_text":"확인"},{"image":"g5_step2_concept_03.png","text":"곱셈 나눗셈이 섞여있을 땐 앞에서부터 차례로 하나씩 계산하면 돼요. 같이 해봐요!","confirm_button_text":"시작해볼까요?"}]},{"cycle_number":2,"cycle_type":"choice","difficulty":1,"questions":[{"image":"g5_step2_c2_q1.png","text":"급식 빵 30개를 5명이 똑같이 나눠 가졌어요. 한 명이 가진 빵을 3배로 늘리면 몇 개일까요?","options":["12개","18개","24개"],"answer":"18개","hint":[["앞에서부터 차례로 계산해봐요!"],["30 ÷ 5 = 6, 6 × 3 = ?"],["거의 다 왔어요! 6 × 3 = □"]],"explanation":"잘했어요! 30 ÷ 5 × 3 = 18개예요."},{"image":"g5_step2_c2_q2.png","text":"급식 도우미 4명이 컵 3개씩 날랐어요. 컵을 2명이 똑같이 나눠 가지면 한 명이 몇 개일까요?","options":["4개","6개","8개"],"answer":"6개","hint":[["앞에서부터 차례로 계산해봐요!"],["4 × 3 = 12, 12 ÷ 2 = ?"],["거의 다 왔어요! 12 ÷ 2 = □"]],"explanation":"잘했어요! 4 × 3 ÷ 2 = 6개예요."},{"image":"g5_step2_c2_q3.png","text":"급식 사과 36개를 4명이 똑같이 나눠 가졌어요. 한 명이 가진 사과를 2배로 늘리면 몇 개일까요?","options":["9개","14개","18개"],"answer":"18개","hint":[["앞에서부터 차례로 계산해봐요!"],["36 ÷ 4 = 9, 9 × 2 = ?"],["거의 다 왔어요! 9 × 2 = □"]],"explanation":"잘했어요! 36 ÷ 4 × 2 = 18개예요."}]},{"cycle_number":3,"cycle_type":"choice","difficulty":2,"questions":[{"image":"g5_step2_c3_q1.png","text":"급식 도우미 3명이 접시 5개씩 날랐어요. 접시를 3명이 똑같이 나눠 정리하면 한 명이 몇 개씩 정리할까요?","options":["3개","5개","7개"],"answer":"5개","hint":[["앞에서부터 차례로 계산해봐요!"],["3 × 5 = 15, 15 ÷ 3 = ?"],["거의 다 왔어요! 15 ÷ 3 = □"]],"explanation":"잘했어요! 3 × 5 ÷ 3 = 5개예요."},{"image":"g5_step2_c3_q2.png","text":"급식 귤 48개를 6명이 똑같이 나눠 가졌어요. 한 명이 가진 귤을 4배로 늘리면 몇 개일까요?","options":["24개","32개","36개"],"answer":"32개","hint":[["앞에서부터 차례로 계산해봐요!"],["48 ÷ 6 = 8, 8 × 4 = ?"],["거의 다 왔어요! 8 × 4 = □"]],"explanation":"잘했어요! 48 ÷ 6 × 4 = 32개예요."},{"image":"g5_step2_c3_q3.png","text":"급식 도우미 5명이 의자 4개씩 날랐어요. 의자를 2명이 똑같이 나눠 정리하면 한 명이 몇 개씩 정리할까요?","options":["8개","10개","12개"],"answer":"10개","hint":[["앞에서부터 차례로 계산해봐요!"],["5 × 4 = 20, 20 ÷ 2 = ?"],["거의 다 왔어요! 20 ÷ 2 = □"]],"explanation":"잘했어요! 5 × 4 ÷ 2 = 10개예요."}]},{"cycle_number":4,"cycle_type":"choice","difficulty":3,"questions":[{"image":"g5_step2_c4_q1.png","text":"급식 도우미 2명이 컵 9개씩 날랐어요. 컵을 6명이 똑같이 나눠 정리하면 한 명이 몇 개씩 정리할까요?","options":["2개","3개","4개"],"answer":"3개","hint":[["앞에서부터 차례로 계산해봐요!"],["2 × 9 = 18, 18 ÷ 6 = ?"],["거의 다 왔어요! 18 ÷ 6 = □"]],"explanation":"잘했어요! 2 × 9 ÷ 6 = 3개예요."},{"image":"g5_step2_c4_q2.png","text":"급식 과자 56개를 8명이 똑같이 나눠 가졌어요. 한 명이 가진 과자를 3배로 늘리면 몇 개일까요?","options":["18개","21개","24개"],"answer":"21개","hint":[["앞에서부터 차례로 계산해봐요!"],["56 ÷ 8 = 7, 7 × 3 = ?"],["거의 다 왔어요! 7 × 3 = □"]],"explanation":"잘했어요! 56 ÷ 8 × 3 = 21개예요."},{"image":"g5_step2_c4_q3.png","text":"급식 도우미 6명이 접시 4개씩 날랐어요. 접시를 8명이 똑같이 나눠 정리하면 한 명이 몇 개씩 정리할까요?","options":["2개","3개","4개"],"answer":"3개","hint":[["앞에서부터 차례로 계산해봐요!"],["6 × 4 = 24, 24 ÷ 8 = ?"],["거의 다 왔어요! 24 ÷ 8 = □"]],"explanation":"잘했어요! 6 × 4 ÷ 8 = 3개예요."}]},{"cycle_number":5,"cycle_type":"short_answer","difficulty":4,"questions":[{"image":"g5_step2_c5_q1.png","text":"급식 사탕 45개를 5명이 똑같이 나눠 가졌어요. 한 명이 가진 사탕을 3배로 늘리면 몇 개일까요?","answer":"27","hint":[["앞에서부터 차례로 계산해봐요!"],["45 ÷ 5 = 9, 9 × 3 = ?"],["거의 다 왔어요! 9 × 3 = □"]],"explanation":"잘했어요! 45 ÷ 5 × 3 = 27개예요."},{"image":"g5_step2_c5_q2.png","text":"급식 도우미 4명이 컵 6개씩 날랐어요. 컵을 3명이 똑같이 나눠 정리하면 한 명이 몇 개씩 정리할까요?","answer":"8","hint":[["앞에서부터 차례로 계산해봐요!"],["4 × 6 = 24, 24 ÷ 3 = ?"],["거의 다 왔어요! 24 ÷ 3 = □"]],"explanation":"잘했어요! 4 × 6 ÷ 3 = 8개예요."},{"image":"g5_step2_c5_q3.png","text":"급식 귤 63개를 7명이 똑같이 나눠 가졌어요. 한 명이 가진 귤을 4배로 늘리면 몇 개일까요?","answer":"36","hint":[["앞에서부터 차례로 계산해봐요!"],["63 ÷ 7 = 9, 9 × 4 = ?"],["거의 다 왔어요! 9 × 4 = □"]],"explanation":"잘했어요! 63 ÷ 7 × 4 = 36개예요."}]}]}'::jsonb)
INSERT INTO math_step (grade, step_number, step_title, concept, content_json) VALUES
(5, 3, '생일 선물 고르기', '덧셈, 뺄셈, 곱셈이 섞여있는 식', '{"subject":"math","step_id":"step_3","step_title":"생일 선물 고르기","grade":5,"semester":1,"unit":1,"concept":"덧셈, 뺄셈, 곱셈이 섞여있는 식","cycles":[{"cycle_number":1,"cycle_type":"concept","slides":[{"image":"g5_step3_concept_01.png","text":"친구 생일 선물을 사러 갔어요! 10000원이 있었어요. 2000원짜리 풍선을 3개 샀어요. 남은 돈은 얼마일까요?","confirm_button_text":"확인"},{"image":"g5_step3_concept_02.png","text":"2000원짜리를 3개 샀으니까 2000 + 2000 + 2000이에요. 같은 수를 여러 번 더할 때는 곱셈으로 써요! 2000 × 3 = 6000원이에요.","confirm_button_text":"확인"},{"image":"g5_step3_concept_03.png","text":"덧셈, 뺄셈, 곱셈이 섞여있으면 곱셈을 먼저 계산해요! 10000 - 2000 × 3 = 10000 - 6000 = 4000원이 남아요!","confirm_button_text":"시작해볼까요?"}]},{"cycle_number":2,"cycle_type":"choice","difficulty":1,"questions":[{"image":"g5_step3_c2_q1.png","text":"10000원이 있었어요. 2000원짜리 풍선을 3개 샀어요. 남은 돈은 얼마일까요?","options":["3000원","4000원","5000원"],"answer":"4000원","hint":[["곱셈을 먼저 계산해봐요!"],["2000 × 3 = 6000, 10000 - 6000 = ?"],["거의 다 왔어요! 10000 - 6000 = □000"]],"explanation":"잘했어요! 10000 - 2000 × 3 = 4000원이에요."},{"image":"g5_step3_c2_q2.png","text":"5000원이 있었어요. 1000원짜리 스티커를 4개 사고, 친구한테 3000원을 받았어요. 지금 돈은 얼마일까요?","options":["4000원","5000원","6000원"],"answer":"4000원","hint":[["곱셈을 먼저 계산해봐요!"],["1000 × 4 = 4000, 5000 - 4000 + 3000 = ?"],["거의 다 왔어요! 5000 - 4000 + 3000 = □000"]],"explanation":"잘했어요! 5000 - 1000 × 4 + 3000 = 4000원이에요."},{"image":"g5_step3_c2_q3.png","text":"8000원이 있었어요. 2000원짜리 선물 포장지를 2개 샀어요. 엄마한테 3000원을 받았어요. 지금 돈은 얼마일까요?","options":["6000원","7000원","8000원"],"answer":"7000원","hint":[["곱셈을 먼저 계산해봐요!"],["2000 × 2 = 4000, 8000 - 4000 + 3000 = ?"],["거의 다 왔어요! 8000 - 4000 + 3000 = □000"]],"explanation":"잘했어요! 8000 - 2000 × 2 + 3000 = 7000원이에요."}]},{"cycle_number":3,"cycle_type":"choice","difficulty":2,"questions":[{"image":"g5_step3_c3_q1.png","text":"3000원이 있었어요. 할머니한테 5000원을 받고, 500원짜리 사탕을 4개 샀어요. 지금 돈은 얼마일까요?","options":["5000원","6000원","7000원"],"answer":"6000원","hint":[["곱셈을 먼저 계산해봐요!"],["500 × 4 = 2000, 3000 + 5000 - 2000 = ?"],["거의 다 왔어요! 3000 + 5000 - 2000 = □000"]],"explanation":"잘했어요! 3000 + 5000 - 500 × 4 = 6000원이에요."},{"image":"g5_step3_c3_q2.png","text":"12000원이 있었어요. 3000원짜리 선물을 3개 샀어요. 친구한테 2000원을 받았어요. 지금 돈은 얼마일까요?","options":["3000원","4000원","5000원"],"answer":"5000원","hint":[["곱셈을 먼저 계산해봐요!"],["3000 × 3 = 9000, 12000 - 9000 + 2000 = ?"],["거의 다 왔어요! 12000 - 9000 + 2000 = □000"]],"explanation":"잘했어요! 12000 - 3000 × 3 + 2000 = 5000원이에요."},{"image":"g5_step3_c3_q3.png","text":"2000원이 있었어요. 아빠한테 8000원을 받고, 1500원짜리 카드를 4개 샀어요. 지금 돈은 얼마일까요?","options":["3000원","4000원","5000원"],"answer":"4000원","hint":[["곱셈을 먼저 계산해봐요!"],["1500 × 4 = 6000, 2000 + 8000 - 6000 = ?"],["거의 다 왔어요! 2000 + 8000 - 6000 = □000"]],"explanation":"잘했어요! 2000 + 8000 - 1500 × 4 = 4000원이에요."}]},{"cycle_number":4,"cycle_type":"choice","difficulty":3,"questions":[{"image":"g5_step3_c4_q1.png","text":"15000원이 있었어요. 2500원짜리 선물 포장지를 4개 사고, 친구한테 3000원을 받았어요. 지금 돈은 얼마일까요?","options":["7000원","8000원","9000원"],"answer":"8000원","hint":[["곱셈을 먼저 계산해봐요!"],["2500 × 4 = 10000, 15000 - 10000 + 3000 = ?"],["거의 다 왔어요! 15000 - 10000 + 3000 = □000"]],"explanation":"잘했어요! 15000 - 2500 × 4 + 3000 = 8000원이에요."},{"image":"g5_step3_c4_q2.png","text":"4000원이 있었어요. 엄마한테 10000원을 받고, 1800원짜리 스티커를 5개 샀어요. 지금 돈은 얼마일까요?","options":["4000원","5000원","6000원"],"answer":"5000원","hint":[["곱셈을 먼저 계산해봐요!"],["1800 × 5 = 9000, 4000 + 10000 - 9000 = ?"],["거의 다 왔어요! 4000 + 10000 - 9000 = □000"]],"explanation":"잘했어요! 4000 + 10000 - 1800 × 5 = 5000원이에요."},{"image":"g5_step3_c4_q3.png","text":"20000원이 있었어요. 3000원짜리 선물을 5개 사고, 할머니한테 5000원을 받았어요. 지금 돈은 얼마일까요?","options":["8000원","9000원","10000원"],"answer":"10000원","hint":[["곱셈을 먼저 계산해봐요!"],["3000 × 5 = 15000, 20000 - 15000 + 5000 = ?"],["거의 다 왔어요! 20000 - 15000 + 5000 = □0000"]],"explanation":"잘했어요! 20000 - 3000 × 5 + 5000 = 10000원이에요."}]},{"cycle_number":5,"cycle_type":"short_answer","difficulty":4,"questions":[{"image":"g5_step3_c5_q1.png","text":"10000원이 있었어요. 2000원짜리 풍선을 3개 사고, 친구한테 4000원을 받았어요. 지금 돈은 얼마일까요?","answer":"8000","hint":[["곱셈을 먼저 계산해봐요!"],["2000 × 3 = 6000, 10000 - 6000 + 4000 = ?"],["거의 다 왔어요! 10000 - 6000 + 4000 = □000"]],"explanation":"잘했어요! 10000 - 2000 × 3 + 4000 = 8000원이에요."},{"image":"g5_step3_c5_q2.png","text":"6000원이 있었어요. 아빠한테 8000원을 받고, 1500원짜리 카드를 6개 샀어요. 지금 돈은 얼마일까요?","answer":"5000","hint":[["곱셈을 먼저 계산해봐요!"],["1500 × 6 = 9000, 6000 + 8000 - 9000 = ?"],["거의 다 왔어요! 6000 + 8000 - 9000 = □000"]],"explanation":"잘했어요! 6000 + 8000 - 1500 × 6 = 5000원이에요."},{"image":"g5_step3_c5_q3.png","text":"18000원이 있었어요. 2500원짜리 선물을 6개 사고, 엄마한테 5000원을 받았어요. 지금 돈은 얼마일까요?","answer":"8000","hint":[["곱셈을 먼저 계산해봐요!"],["2500 × 6 = 15000, 18000 - 15000 + 5000 = ?"],["거의 다 왔어요! 18000 - 15000 + 5000 = □000"]],"explanation":"잘했어요! 18000 - 2500 × 6 + 5000 = 8000원이에요."}]}]}'::jsonb)
INSERT INTO math_step (grade, step_number, step_title, concept, content_json) VALUES
(6, 1, '재료 나눠 담기 (1)', '자연수 ÷ 자연수의 몫을 분수로 나타내기', '{"subject":"math","step_id":"step_1","step_title":"재료 나눠 담기 (1)","grade":6,"semester":1,"unit":1,"concept":"자연수 ÷ 자연수의 몫을 분수로 나타내기","cycles":[{"cycle_number":1,"cycle_type":"concept","slides":[{"image":"g6_step1_concept_01.png","text":[{"type":"text","value":"밀가루 3kg을 4봉지에 똑같이 나눠 담으려고 해요. 한 봉지에 몇 kg씩 담으면 될까요?"}],"confirm_button_text":"확인"},{"image":"g6_step1_concept_02.png","text":[{"type":"text","value":"3 ÷ 4는 딱 나눠지지 않아요. 이럴 때는 분수로 나타낼 수 있어요! 나눠지는 수 3이 분자, 나누는 수 4가 분모가 돼요. 3 ÷ 4 = "},{"type":"fraction","numerator":3,"denominator":4},{"type":"text","value":"예요!"}],"confirm_button_text":"확인"},{"image":"g6_step1_concept_03.png","text":[{"type":"text","value":"자연수 ÷ 자연수는 분수로 나타낼 수 있어요. 한 봉지에 "},{"type":"fraction","numerator":3,"denominator":4},{"type":"text","value":"kg씩 담으면 돼요. 같이 해봐요!"}],"confirm_button_text":"시작해볼까요?"}]},{"cycle_number":2,"cycle_type":"choice","difficulty":1,"questions":[{"image":"g6_step1_c2_q1.png","text":[{"type":"text","value":"소금 2kg을 3봉지에 똑같이 나눠 담으면 한 봉지에 몇 kg씩 담을 수 있을까요?"}],"options":[{"display":"fraction","numerator":1,"denominator":3,"unit":"kg"},{"display":"fraction","numerator":2,"denominator":3,"unit":"kg"},{"display":"fraction","numerator":3,"denominator":2,"unit":"kg"}],"answer":{"numerator":2,"denominator":3,"unit":"kg"},"hint":[[{"type":"text","value":"2 ÷ 3을 분수로 나타내봐요!"}],[{"type":"text","value":"나눠지는 수 2가 분자, 나누는 수 3이 분모가 돼요."}],[{"type":"text","value":"거의 다 왔어요! 2 ÷ 3 = "},{"type":"fraction","numerator":2,"denominator":3}]],"explanation":[{"type":"text","value":"잘했어요! 2 ÷ 3 = "},{"type":"fraction","numerator":2,"denominator":3},{"type":"text","value":"kg이에요."}]},{"image":"g6_step1_c2_q2.png","text":[{"type":"text","value":"설탕 5kg을 7봉지에 똑같이 나눠 담으면 한 봉지에 몇 kg씩 담을 수 있을까요?"}],"options":[{"display":"fraction","numerator":5,"denominator":7,"unit":"kg"},{"display":"fraction","numerator":7,"denominator":5,"unit":"kg"},{"display":"fraction","numerator":2,"denominator":7,"unit":"kg"}],"answ