INSERT INTO korean_step (grade, step_number, step_title, concept, content_json) VALUES
(3, 1, '비 오는 날', '감각적 표현, 흉내말', '{"subject":"korean","step_id":"grade3_step1","step_title":"비 오는 날","grade":3,"unit_concept":["감각적 표현","흉내말"],"passage":{"title":"비 오는 날","text":"오늘은 비가 주룩주룩 내렸어요. 민준이는 창문 너머로 빗소리를 들으며 앉아 있었어요. 후두둑후두둑, 빗방울이 지붕을 두드렸어요. 흙냄새가 코끝에 살며시 풍겨왔어요. 민준이는 촉촉하게 젖은 꽃잎을 바라보며 미소를 지었어요.","image":"passage_grade3_step1.png"},"cycles":[{"cycle_number":1,"cycle_type":"word_card","slides":[{"word":"주룩주룩","image":"word_jururuk.png","description":"비가 많이 내릴 때 나는 소리예요!","confirm_button_text":"이해했어!"},{"word":"후두둑","image":"word_hududuk.png","description":"굵은 빗방울이 떨어질 때 나는 소리예요!","confirm_button_text":"이해했어!"},{"word":"촉촉","image":"word_chokcchok.png","description":"물기가 살짝 있어서 부드러운 느낌이에요!","confirm_button_text":"시작해볼게!"}]},{"cycle_number":2,"cycle_type":"fact_check","questions":[{"question_id":1,"related_sentence":"오늘은 비가 주룩주룩 내렸어요.","question":"오늘 날씨는 비가 왔나요?","options":["O","X"],"answer":"O","hints":[["첫 번째 문장을 다시 읽어봐요!"],["''비가 주룩주룩''이라는 표현이 있어요. 찾았나요?"]]},{"question_id":2,"related_sentence":"민준이는 창문 너머로 빗소리를 들으며 앉아 있었어요.","question":"민준이는 밖에 나가서 비를 맞았나요?","options":["O","X"],"answer":"X","hints":[["민준이가 어디에 있었는지 찾아봐요!"],["''창문 너머로''라고 했어요. 창문 안에서 보고 있었던 거예요!"]]},{"question_id":3,"related_sentence":"흙냄새가 코끝에 살며시 풍겨왔어요.","question":"민준이가 느낀 것은 무엇인가요?","options":["흙냄새","꽃향기","빵냄새"],"answer":"흙냄새","hints":[["코로 느낀 것을 글에서 찾아봐요!"],["''코끝에 풍겨왔어요''라는 문장을 읽어봐요. 거의 다 왔어요!"]]}]},{"cycle_number":3,"cycle_type":"diagram_order","diagram_type":"sequence","boxes":[{"id":1,"is_blank":true},{"id":2,"is_blank":false,"content":"빗소리를 들으며 창가에 앉았다"},{"id":3,"is_blank":true}],"questions":[{"question_id":1,"target_box":1,"related_sentence":"오늘은 비가 주룩주룩 내렸어요.","question":"가장 먼저 일어난 일은 무엇인가요?","options":["비가 내리기 시작했다","흙냄새가 났다","꽃잎을 바라봤다"],"answer":"비가 내리기 시작했다","hints":[["이야기에서 맨 처음 일어난 일을 찾아봐요!"],["글의 첫 번째 문장을 읽어봐요. 할 수 있어요!"]]},{"question_id":2,"target_box":3,"related_sentence":"민준이는 촉촉하게 젖은 꽃잎을 바라보며 미소를 지었어요.","question":"마지막에 민준이가 한 일은 무엇인가요?","options":["밖으로 나갔다","젖은 꽃잎을 보며 미소 지었다","창문을 닫았다"],"answer":"젖은 꽃잎을 보며 미소 지었다","hints":[["이야기의 마지막 문장을 찾아봐요!"],["''미소를 지었어요''라는 표현이 있어요. 찾았나요?"]]},{"question_id":3,"target_box":2,"related_sentence":"민준이는 창문 너머로 빗소리를 들으며 앉아 있었어요.","question":"빗소리를 들으며 민준이는 어디에 있었나요?","options":["마당","창가","학교"],"answer":"창가","hints":[["민준이가 빗소리를 어디서 들었는지 찾아봐요!"],["''창문 너머로''라는 표현에서 힌트를 얻어봐요. 거의 다 왔어요!"]]}]},{"cycle_number":4,"cycle_type":"inference","questions":[{"question_id":1,"scene_image":"scene_rain_window.png","related_sentence":"민준이는 촉촉하게 젖은 꽃잎을 바라보며 미소를 지었어요.","question":"꽃잎을 보면서 민준이는 어떤 기분이었을까요?","options":["행복했을 것이다","무서웠을 것이다","화가 났을 것이다"],"answer":"행복했을 것이다","hints":[["미소를 짓는다는 건 어떤 기분일 때일까요?"],["기분이 좋을 때 우리도 미소를 짓잖아요. 맞아요, 잘하고 있어요!"]]},{"question_id":2,"scene_image":"scene_rain_smell.png","related_sentence":"흙냄새가 코끝에 살며시 풍겨왔어요.","question":"''살며시 풍겨온다''는 게 어떤 뜻인가요?","options":["아주 강하게 확 나는 것","살짝 부드럽게 나는 것","전혀 안 나는 것"],"answer":"살짝 부드럽게 나는 것","hints":[["''살며시''가 어떤 뜻인지 생각해봐요!"],["살며시는 아주 조용하고 부드럽게라는 뜻이에요. 거의 다 왔어요!"]]},{"question_id":3,"scene_image":"scene_rain_sound.png","related_sentence":"후두둑후두둑, 빗방울이 지붕을 두드렸어요.","question":"빗방울이 지붕을 두드린다고 했어요. 빗방울을 무엇처럼 나타낸 건가요?","options":["사람이 손으로 두드리는 것처럼","새가 날아가는 것처럼","물이 흘러가는 것처럼"],"answer":"사람이 손으로 두드리는 것처럼","hints":[["''두드렸어요''는 누가 하는 행동인지 생각해봐요!"],["사람이 문을 두드리는 것처럼, 빗방울도 지붕을 두드린다고 했어요. 잘하고 있어요!"]]}]},{"cycle_number":5,"cycle_type":"summary_fill","summary_template":"오늘은 비가 [BLANK_1] 내렸어요. 민준이는 창가에 앉아 빗소리를 들었어요. 흙냄새가 코끝에 풍겨오고, 젖은 꽃잎을 바라보며 민준이는 [BLANK_2] 기분이 들었어요.","questions":[{"question_id":1,"target_blank":"BLANK_1","question":"비가 어떻게 내렸나요?","options":["주룩주룩","펑펑","살살"],"answer":"주룩주룩","hints":[["비가 내리는 소리를 나타내는 흉내말이에요!"],["비가 많이 내릴 때 쓰는 표현이에요. 거의 다 왔어요!"]]},{"question_id":2,"target_blank":"BLANK_2","question":"꽃잎을 바라보며 민준이는 어떤 기분이 들었나요?","options":["행복한","슬픈","무서운"],"answer":"행복한","hints":[["꽃잎을 보며 미소를 지었어요. 미소를 지을 때는 어떤 기분인가요?"],["미소를 지을 때는 기분이 좋을 때예요. 할 수 있어요!"]]},{"question_id":3,"target_blank":null,"question":"이 글에서 비 오는 소리를 나타낸 낱말은 무엇인가요?","options":["후두둑후두둑","쨍그랑쨍그랑","펑펑"],"answer":"후두둑후두둑","hints":[["빗방울이 지붕을 두드리는 소리를 나타낸 낱말이에요!"],["''후''로 시작하는 낱말이에요. 거의 다 왔어요!"]]}]}]}'::jsonb)
INSERT INTO korean_step (grade, step_number, step_title, concept, content_json) VALUES
(3, 2, '할머니 댁 방문', '높임 표현, 상황 판단', '{"subject":"korean","step_id":"grade3_step2","step_title":"할머니 댁 방문","grade":3,"unit_concept":["높임 표현","상황 판단"],"passage":{"title":"할머니 댁 방문","text":"주말에 지수는 할머니 댁에 갔어요. 지수는 할머니께 꽃을 드렸어요. 할머니께서는 환하게 웃으시며 고맙다고 하셨어요. 지수는 할머니께 ''진지 잡수셨어요?'' 하고 여쭤봤어요. 할머니께서는 ''그래, 먹었단다.'' 하고 대답하셨어요.","image":"passage_grade3_step2.png"},"cycles":[{"cycle_number":1,"cycle_type":"word_card","slides":[{"word":"드리다","image":"word_deurida.png","description":"웃어른께 선물이나 물건을 줄 때 쓰는 말이에요!","confirm_button_text":"이해했어!"},{"word":"여쭤보다","image":"word_yeojjwoboda.png","description":"웃어른께 무언가 물어볼 때 쓰는 말이에요!","confirm_button_text":"이해했어!"},{"word":"잡수시다","image":"word_jabsusida.png","description":"웃어른이 음식을 드실 때 쓰는 말이에요!","confirm_button_text":"시작해볼게!"}]},{"cycle_number":2,"cycle_type":"fact_check","questions":[{"question_id":1,"related_sentence":"주말에 지수는 할머니 댁에 갔어요.","question":"지수는 주말에 할머니 댁에 갔나요?","options":["O","X"],"answer":"O","hints":[["첫 번째 문장을 다시 읽어봐요!"],["''주말에 지수는 할머니 댁에''라는 표현이 있어요. 찾았나요?"]]},{"question_id":2,"related_sentence":"지수는 할머니께 꽃을 드렸어요.","question":"지수가 할머니께 드린 것은 무엇인가요?","options":["꽃","사탕","책"],"answer":"꽃","hints":[["지수가 할머니께 무엇을 드렸는지 글에서 찾아봐요!"],["''꽃을 드렸어요''라는 표현이 있어요. 거의 다 왔어요!"]]},{"question_id":3,"related_sentence":"할머니께서는 환하게 웃으시며 고맙다고 하셨어요.","question":"꽃을 받은 할머니의 표정은 어땠나요?","options":["환하게 웃으셨다","화가 나셨다","슬퍼하셨다"],"answer":"환하게 웃으셨다","hints":[["할머니의 표정을 글에서 찾아봐요!"],["''환하게 웃으시며''라는 표현이 있어요. 찾았나요?"]]}]},{"cycle_number":3,"cycle_type":"diagram_order","diagram_type":"sequence","boxes":[{"id":1,"is_blank":true},{"id":2,"is_blank":false,"content":"할머니께 꽃을 드렸다"},{"id":3,"is_blank":true}],"questions":[{"question_id":1,"target_box":1,"related_sentence":"주말에 지수는 할머니 댁에 갔어요.","question":"가장 먼저 일어난 일은 무엇인가요?","options":["할머니 댁에 갔다","진지를 여쭤봤다","할머니께서 웃으셨다"],"answer":"할머니 댁에 갔다","hints":[["이야기에서 맨 처음 일어난 일을 찾아봐요!"],["글의 첫 번째 문장을 읽어봐요. 할 수 있어요!"]]},{"question_id":2,"target_box":3,"related_sentence":"지수는 할머니께 ''진지 잡수셨어요?'' 하고 여쭤봤어요.","question":"마지막에 지수가 한 일은 무엇인가요?","options":["할머니께 진지를 여쭤봤다","할머니 댁을 떠났다","할머니께 꽃을 드렸다"],"answer":"할머니께 진지를 여쭤봤다","hints":[["이야기의 마지막 부분을 찾아봐요!"],["''여쭤봤어요''라는 표현이 있어요. 거의 다 왔어요!"]]},{"question_id":3,"target_box":2,"related_sentence":"지수는 할머니께 꽃을 드렸어요.","question":"지수가 할머니께 꽃을 드린 것은 몇 번째 일인가요?","options":["첫 번째","두 번째","세 번째"],"answer":"두 번째","hints":[["첫 번째 일이 무엇인지 먼저 생각해봐요!"],["할머니 댁에 도착한 다음에 한 일이에요. 찾았나요?"]]}]},{"cycle_number":4,"cycle_type":"inference","questions":[{"question_id":1,"scene_image":"scene_grandma_flower.png","related_sentence":"할머니께서는 환하게 웃으시며 고맙다고 하셨어요.","question":"꽃을 받은 할머니는 어떤 기분이었을까요?","options":["기쁘셨을 것이다","무서우셨을 것이다","심심하셨을 것이다"],"answer":"기쁘셨을 것이다","hints":[["환하게 웃는다는 건 어떤 기분일 때일까요?"],["기분이 좋을 때 우리도 환하게 웃잖아요. 맞아요, 잘하고 있어요!"]]},{"question_id":2,"scene_image":"scene_grandma_talk.png","related_sentence":"지수는 할머니께 ''진지 잡수셨어요?'' 하고 여쭤봤어요.","question":"지수가 ''진지 잡수셨어요?''라고 한 까닭은 무엇일까요?","options":["할머니를 걱정하고 아끼기 때문이다","할머니가 무섭기 때문이다","밥이 먹고 싶었기 때문이다"],"answer":"할머니를 걱정하고 아끼기 때문이다","hints":[["누군가에게 밥 먹었는지 물어볼 때는 어떤 마음일까요?"],["밥을 먹었는지 물어보는 건 그 사람이 걱정되기 때문이에요. 거의 다 왔어요!"]]},{"question_id":3,"scene_image":"scene_grandma_speak.png","related_sentence":"지수는 할머니께 ''진지 잡수셨어요?'' 하고 여쭤봤어요.","question":"지수가 ''밥 먹었어?'' 대신 ''진지 잡수셨어요?''라고 한 까닭은 무엇인가요?","options":["할머니는 웃어른이라 높임말을 써야 하기 때문이다","진지가 더 짧은 말이기 때문이다","할머니가 좋아하는 말이기 때문이다"],"answer":"할머니는 웃어른이라 높임말을 써야 하기 때문이다","hints":[["할머니는 지수보다 나이가 많은 웃어른이에요!"],["웃어른께는 높임말을 써야 해요. 잘하고 있어요!"]]}]},{"cycle_number":5,"cycle_type":"summary_fill","summary_template":"지수는 주말에 할머니 댁에 갔어요. 할머니께 꽃을 [BLANK_1] 할머니께서 환하게 웃으셨어요. 지수는 할머니께 높임말로 [BLANK_2] 하고 여쭤봤어요.","questions":[{"question_id":1,"target_blank":"BLANK_1","question":"지수가 할머니께 꽃을 어떻게 했나요?","options":["드렸더니","줬더니","던졌더니"],"answer":"드렸더니","hints":[["웃어른께 물건을 줄 때 쓰는 높임말이에요!"],["''드리다''를 사용한 표현이에요. 거의 다 왔어요!"]]},{"question_id":2,"target_blank":"BLANK_2","question":"지수가 할머니께 뭐라고 여쭤봤나요?","options":["''진지 잡수셨어요?''","''밥 먹었어?''","''밥은요?''"],"answer":"''진지 잡수셨어요?''","hints":[["할머니는 웃어른이라 높임말을 써야 해요!"],["''진지''와 ''잡수시다''가 들어간 표현이에요. 할 수 있어요!"]]},{"question_id":3,"target_blank":null,"question":"웃어른께 물어볼 때 쓰는 말은 무엇인가요?","options":["여쭤보다","물어보다","말하다"],"answer":"여쭤보다","hints":[["웃어른께 질문할 때 쓰는 높임말이에요!"],["''여''로 시작하는 낱말이에요. 거의 다 왔어요!"]]}]}]}'::jsonb)
INSERT INTO korean_step (grade, step_number, step_title, concept, content_json) VALUES
(3, 3, '토끼와 거북이', '원인과 결과, 감정 추론', '{"subject":"korean","step_id":"grade3_step3","step_title":"토끼와 거북이","grade":3,"unit_concept":["원인과 결과","감정 추론"],"passage":{"title":"토끼와 거북이","text":"토끼와 거북이가 달리기 시합을 했어요. 토끼는 너무 자신만만해서 중간에 낮잠을 잤어요. 거북이는 쉬지 않고 열심히 달렸어요. 잠에서 깬 토끼가 결승점으로 달려갔지만, 거북이가 먼저 도착해 있었어요. 거북이가 시합에서 이겼어요.","image":"passage_grade3_step3.png"},"cycles":[{"cycle_number":1,"cycle_type":"word_card","slides":[{"word":"자신만만","image":"word_jasinmanman.png","description":"내가 꼭 잘할 수 있다고 아주 굳게 믿는 것이에요!","confirm_button_text":"이해했어!"},{"word":"결승점","image":"word_gyeolseungjeom.png","description":"달리기나 시합에서 맨 마지막에 도착하는 곳이에요!","confirm_button_text":"이해했어!"},{"word":"시합","image":"word_sihap.png","description":"누가 더 잘하는지 겨루는 것이에요!","confirm_button_text":"시작해볼게!"}]},{"cycle_number":2,"cycle_type":"fact_check","questions":[{"question_id":1,"related_sentence":"토끼와 거북이가 달리기 시합을 했어요.","question":"토끼와 거북이는 달리기 시합을 했나요?","options":["O","X"],"answer":"O","hints":[["첫 번째 문장을 다시 읽어봐요!"],["''달리기 시합을 했어요''라는 표현이 있어요. 찾았나요?"]]},{"question_id":2,"related_sentence":"토끼는 너무 자신만만해서 중간에 낮잠을 잤어요.","question":"토끼는 시합 중간에 무엇을 했나요?","options":["낮잠을 잤다","밥을 먹었다","친구를 만났다"],"answer":"낮잠을 잤다","hints":[["토끼가 시합 중간에 한 일을 글에서 찾아봐요!"],["''중간에 낮잠을''이라는 표현이 있어요. 거의 다 왔어요!"]]},{"question_id":3,"related_sentence":"거북이가 시합에서 이겼어요.","question":"시합에서 이긴 것은 누구인가요?","options":["거북이","토끼","둘 다"],"answer":"거북이","hints":[["마지막 문장을 읽어봐요!"],["''거북이가 시합에서 이겼어요''라고 되어 있어요. 찾았나요?"]]}]},{"cycle_number":3,"cycle_type":"diagram_order","diagram_type":"cause_effect","boxes":[{"id":1,"is_blank":false,"content":"토끼가 자신만만해서 낮잠을 잤다"},{"id":2,"is_blank":true},{"id":3,"is_blank":true},{"id":4,"is_blank":true}],"questions":[{"question_id":1,"target_box":2,"related_sentence":"잠에서 깬 토끼가 결승점으로 달려갔지만, 거북이가 먼저 도착해 있었어요.","question":"토끼가 낮잠을 잔 결과는 무엇인가요?","options":["토끼가 시합에서 졌다","토끼가 시합에서 이겼다","시합이 취소됐다"],"answer":"토끼가 시합에서 졌다","hints":[["낮잠을 자고 나서 토끼에게 어떤 일이 생겼는지 찾아봐요!"],["거북이가 먼저 결승점에 도착했다고 했어요. 거의 다 왔어요!"]]},{"question_id":2,"target_box":3,"related_sentence":"거북이는 쉬지 않고 열심히 달렸어요.","question":"거북이는 시합에서 어떻게 했나요?","options":["쉬지 않고 열심히 달렸다","중간에 쉬었다","포기했다"],"answer":"쉬지 않고 열심히 달렸다","hints":[["거북이가 시합 내내 어떻게 했는지 글에서 찾아봐요!"],["''쉬지 않고 열심히''라는 표현이 있어요. 찾았나요?"]]},{"question_id":3,"target_box":4,"related_sentence":"거북이가 시합에서 이겼어요.","question":"거북이가 쉬지 않고 달린 결과는 무엇인가요?","options":["거북이가 시합에서 이겼다","거북이가 넘어졌다","거북이가 포기했다"],"answer":"거북이가 시합에서 이겼다","hints":[["열심히 달린 거북이에게 어떤 일이 생겼는지 찾아봐요!"],["마지막 문장을 읽어봐요. 할 수 있어요!"]]}]},{"cycle_number":4,"cycle_type":"inference","questions":[{"question_id":1,"scene_image":"scene_rabbit_lose.png","related_sentence":"잠에서 깬 토끼가 결승점으로 달려갔지만, 거북이가 먼저 도착해 있었어요.","question":"시합에서 진 토끼는 어떤 기분이었을까요?","options":["부끄럽고 속상했을 것이다","신나고 기뻤을 것이다","무섭고 떨렸을 것이다"],"answer":"부끄럽고 속상했을 것이다","hints":[["내가 자신 있었는데 졌다면 어떤 기분일까요?"],["자신만만했는데 지면 부끄럽고 속상하잖아요. 맞아요, 잘하고 있어요!"]]},{"question_id":2,"scene_image":"scene_turtle_win.png","related_sentence":"거북이가 시합에서 이겼어요.","question":"시합에서 이긴 거북이는 어떤 기분이었을까요?","options":["뿌듯하고 기뻤을 것이다","슬프고 힘들었을 것이다","화가 났을 것이다"],"answer":"뿌듯하고 기뻤을 것이다","hints":[["열심히 달려서 이겼을 때 어떤 기분일까요?"],["열심히 노력해서 이기면 뿌듯하고 기쁘잖아요. 거의 다 왔어요!"]]},{"question_id":3,"scene_image":"scene_turtle_run.png","related_sentence":"거북이는 쉬지 않고 열심히 달렸어요.","question":"거북이가 쉬지 않고 달린 까닭은 무엇일까요?","options":["이기고 싶어서 최선을 다했기 때문이다","토끼가 무서웠기 때문이다","결승점이 가까웠기 때문이다"],"answer":"이기고 싶어서 최선을 다했기 때문이다","hints":[["거북이는 왜 쉬지 않고 달렸을까요?"],["시합에서 이기고 싶으면 어떻게 해야 할까요? 할 수 있어요!"]]}]},{"cycle_number":5,"cycle_type":"summary_fill","summary_template":"토끼와 거북이가 달리기 시합을 했어요. 토끼는 자신만만해서 [BLANK_1] 거북이는 쉬지 않고 열심히 달렸어요. 결국 [BLANK_2] 시합에서 이겼어요.","questions":[{"question_id":1,"target_blank":"BLANK_1","question":"토끼는 시합 중간에 무엇을 했나요?","options":["낮잠을 잤어요.","밥을 먹었어요.","집에 갔어요."],"answer":"낮잠을 잤어요.","hints":[["자신만만한 토끼가 시합 중간에 한 일이에요!"],["''낮잠''이 들어간 표현이에요. 거의 다 왔어요!"]]},{"question_id":2,"target_blank":"BLANK_2","question":"시합에서 이긴 것은 누구인가요?","options":["거북이가","토끼가","둘 다"],"answer":"거북이가","hints":[["열심히 쉬지 않고 달린 쪽이 이겼어요!"],["마지막 문장을 떠올려봐요. 할 수 있어요!"]]},{"question_id":3,"target_blank":null,"question":"거북이가 시합에서 이긴 까닭은 무엇인가요?","options":["쉬지 않고 열심히 달렸기 때문이다","토끼보다 빠르기 때문이다","토끼가 도와줬기 때문이다"],"answer":"쉬지 않고 열심히 달렸기 때문이다","hints":[["거북이가 시합 내내 어떻게 했는지 떠올려봐요!"],["''쉬지 않고 열심히''라는 표현이 힌트예요. 잘하고 있어요!"]]}]}]}'::jsonb)
INSERT INTO korean_step (grade, step_number, step_title, concept, content_json) VALUES
(4, 1, '화폐는 왜 생겼을까', '중심 생각 파악, 어휘 이해', '{"subject":"korean","step_id":"grade4_step1","step_title":"화폐는 왜 생겼을까","grade":4,"unit_concept":["중심 생각 파악","어휘 이해"],"passage":{"title":"화폐는 왜 생겼을까","text":"옛날 사람들은 물건을 서로 바꾸는 방법으로 거래를 했어요. 하지만 원하는 물건을 가진 사람을 찾기가 너무 어려웠어요. 그래서 사람들은 누구나 원하는 것, 바로 화폐를 만들었어요. 화폐가 생기면서 물건을 훨씬 쉽고 편리하게 사고팔 수 있게 되었어요. 화폐는 우리 생활을 편리하게 해 주는 중요한 도구예요.","image":"passage_grade4_step1.png"},"cycles":[{"cycle_number":1,"cycle_type":"word_card","slides":[{"word":"거래","image":"word_geolle.png","description":"물건이나 돈을 서로 주고받는 것이에요!","confirm_button_text":"이해했어!"},{"word":"화폐","image":"word_hwapye.png","description":"물건을 사고팔 때 쓰는 돈이에요!","confirm_button_text":"이해했어!"},{"word":"편리하다","image":"word_pyeolliha.png","description":"어렵지 않고 쓰기 쉬운 것이에요!","confirm_button_text":"시작해볼게!"}]},{"cycle_number":2,"cycle_type":"fact_check","questions":[{"question_id":1,"related_sentence":"옛날 사람들은 물건을 서로 바꾸는 방법으로 거래를 했어요.","question":"옛날 사람들은 돈 없이 물건을 서로 바꿨나요?","options":["O","X"],"answer":"O","hints":[["첫 번째 문장을 다시 읽어봐요!"],["''물건을 서로 바꾸는 방법으로''라는 표현이 있어요. 찾았나요?"]]},{"question_id":2,"related_sentence":"하지만 원하는 물건을 가진 사람을 찾기가 너무 어려웠어요.","question":"옛날에 거래가 어려웠던 까닭은 무엇인가요?","options":["원하는 물건을 가진 사람 찾기가 어려워서","물건이 너무 무거워서","가게가 너무 멀어서"],"answer":"원하는 물건을 가진 사람 찾기가 어려워서","hints":[["거래가 어려웠던 이유를 글에서 찾아봐요!"],["''원하는 물건을 가진 사람을 찾기가''라는 표현이 있어요. 거의 다 왔어요!"]]},{"question_id":3,"related_sentence":"화폐가 생기면서 물건을 훨씬 쉽고 편리하게 사고팔 수 있게 되었어요.","question":"화폐가 생기면서 거래는 어떻게 바뀌었나요?","options":["더 쉽고 편리해졌다","더 어려워졌다","달라진 게 없다"],"answer":"더 쉽고 편리해졌다","hints":[["화폐가 생긴 뒤 어떻게 되었는지 글에서 찾아봐요!"],["''쉽고 편리하게''라는 표현이 있어요. 찾았나요?"]]}]},{"cycle_number":3,"cycle_type":"diagram_order","diagram_type":"cause_effect","boxes":[{"id":1,"is_blank":false,"content":"원하는 물건을 가진 사람 찾기가 너무 어려웠다"},{"id":2,"is_blank":true},{"id":3,"is_blank":true},{"id":4,"is_blank":true}],"questions":[{"question_id":1,"target_box":2,"related_sentence":"그래서 사람들은 누구나 원하는 것, 바로 화폐를 만들었어요.","question":"거래가 어려워진 결과 사람들은 무엇을 만들었나요?","options":["화폐를 만들었다","시장을 만들었다","지도를 만들었다"],"answer":"화폐를 만들었다","hints":[["거래가 어려워서 사람들이 무엇을 했는지 찾아봐요!"],["''그래서 사람들은''으로 시작하는 문장을 읽어봐요. 거의 다 왔어요!"]]},{"question_id":2,"target_box":3,"related_sentence":"화폐가 생기면서 물건을 훨씬 쉽고 편리하게 사고팔 수 있게 되었어요.","question":"화폐가 생긴 결과는 무엇인가요?","options":["물건을 쉽고 편리하게 사고팔 수 있게 됐다","물건 값이 비싸졌다","거래가 더 어려워졌다"],"answer":"물건을 쉽고 편리하게 사고팔 수 있게 됐다","hints":[["화폐가 생긴 뒤 어떤 일이 일어났는지 찾아봐요!"],["''쉽고 편리하게 사고팔 수 있게''라는 표현이 있어요. 할 수 있어요!"]]},{"question_id":3,"target_box":4,"related_sentence":"화폐는 우리 생활을 편리하게 해 주는 중요한 도구예요.","question":"이 글에서 화폐는 어떤 것이라고 했나요?","options":["생활을 편리하게 해 주는 중요한 도구","사람들이 좋아하는 예쁜 물건","오래전에 사라진 물건"],"answer":"생활을 편리하게 해 주는 중요한 도구","hints":[["글의 마지막 문장을 읽어봐요!"],["''편리하게 해 주는 중요한''이라는 표현이 있어요. 찾았나요?"]]}]},{"cycle_number":4,"cycle_type":"inference","questions":[{"question_id":1,"scene_image":"scene_trade_old.png","related_sentence":"하지만 원하는 물건을 가진 사람을 찾기가 너무 어려웠어요.","question":"원하는 물건을 가진 사람을 못 찾았을 때 옛날 사람들은 어떤 기분이었을까요?","options":["답답하고 불편했을 것이다","신나고 즐거웠을 것이다","편안하고 행복했을 것이다"],"answer":"답답하고 불편했을 것이다","hints":[["원하는 걸 못 구하면 어떤 기분일까요?"],["원하는 걸 못 찾으면 답답하고 불편하잖아요. 잘하고 있어요!"]]},{"question_id":2,"scene_image":"scene_money_easy.png","related_sentence":"화폐가 생기면서 물건을 훨씬 쉽고 편리하게 사고팔 수 있게 되었어요.","question":"화폐가 생긴 뒤 사람들은 어떤 기분이었을까요?","options":["편리해져서 기뻤을 것이다","화폐가 무서웠을 것이다","화폐가 필요 없었을 것이다"],"answer":"편리해져서 기뻤을 것이다","hints":[["어렵던 거래가 쉬워지면 어떤 기분일까요?"],["불편했던 것이 편리해지면 기쁘잖아요. 거의 다 왔어요!"]]},{"question_id":3,"scene_image":"scene_money_important.png","related_sentence":"화폐는 우리 생활을 편리하게 해 주는 중요한 도구예요.","question":"이 글을 쓴 사람은 화폐에 대해 어떻게 생각하고 있나요?","options":["화폐는 우리에게 꼭 필요하고 중요하다","화폐는 없어도 된다","화폐는 위험한 것이다"],"answer":"화폐는 우리에게 꼭 필요하고 중요하다","hints":[["글쓴이가 화폐를 어떤 말로 표현했는지 찾아봐요!"],["''중요한 도구''라는 표현이 있어요. 찾았나요?"]]}]},{"cycle_number":5,"cycle_type":"summary_fill","summary_template":"옛날 사람들은 물건을 서로 바꾸며 거래했지만 [BLANK_1] 그래서 사람들은 화폐를 만들었어요. 화폐 덕분에 물건을 [BLANK_2] 사고팔 수 있게 되었어요.","questions":[{"question_id":1,"target_blank":"BLANK_1","question":"옛날 거래에서 어떤 점이 어려웠나요?","options":["원하는 물건을 가진 사람 찾기가 너무 어려웠어요.","물건이 너무 무거웠어요.","가게가 너무 멀었어요."],"answer":"원하는 물건을 가진 사람 찾기가 너무 어려웠어요.","hints":[["옛날 거래의 불편한 점을 글에서 찾아봐요!"],["두 번째 문장에 힌트가 있어요. 거의 다 왔어요!"]]},{"question_id":2,"target_blank":"BLANK_2","question":"화폐 덕분에 거래는 어떻게 바뀌었나요?","options":["쉽고 편리하게","느리고 불편하게","비싸고 어렵게"],"answer":"쉽고 편리하게","hints":[["화폐가 생긴 뒤 거래가 어떻게 바뀌었는지 떠올려봐요!"],["''쉽고 편리하게''라는 표현이 힌트예요. 할 수 있어요!"]]},{"question_id":3,"target_blank":null,"question":"이 글의 중심 생각은 무엇인가요?","options":["화폐는 거래를 편리하게 해 주는 중요한 도구이다","옛날 사람들은 물건 바꾸기를 좋아했다","화폐는 예쁘고 갖고 싶은 물건이다"],"answer":"화폐는 거래를 편리하게 해 주는 중요한 도구이다","hints":[["이 글 전체에서 가장 하고 싶은 말이 뭔지 생각해봐요!"],["마지막 문장에 중심 생각이 담겨 있어요. 잘하고 있어요!"]]}]}]}'::jsonb)
INSERT INTO korean_step (grade, step_number, step_title, concept, content_json) VALUES
(4, 2, '오세암의 길동이', '인물 마음 짐작하기, 이야기 흐름 파악', '{"subject":"korean","step_id":"grade4_step2","step_title":"오세암의 길동이","grade":4,"unit_concept":["인물 마음 짐작하기","이야기 흐름 파악"],"passage":{"title":"오세암의 길동이","text":"길동이는 눈 덮인 산속 암자에 혼자 남겨졌어요. 처음에는 누나가 곧 돌아올 거라 생각해서 무섭지 않았어요. 하지만 날이 어두워지고 누나가 오지 않자 길동이는 점점 불안해졌어요. 길동이는 관세음보살님께 누나가 빨리 오게 해달라고 빌고 또 빌었어요. 추운 밤이 지나고 아침이 되었지만 누나는 여전히 오지 않았어요.","image":"passage_grade4_step2.png"},"cycles":[{"cycle_number":1,"cycle_type":"word_card","slides":[{"word":"암자","image":"word_amja.png","description":"산속에 있는 작고 조용한 절이에요!","confirm_button_text":"이해했어!"},{"word":"불안하다","image":"word_buranha.png","description":"마음이 편하지 않고 걱정되는 느낌이에요!","confirm_button_text":"이해했어!"},{"word":"여전히","image":"word_yeojeonhi.png","description":"전과 똑같이 변함이 없다는 뜻이에요!","confirm_button_text":"시작해볼게!"}]},{"cycle_number":2,"cycle_type":"fact_check","questions":[{"question_id":1,"related_sentence":"길동이는 눈 덮인 산속 암자에 혼자 남겨졌어요.","question":"길동이는 산속 암자에 혼자 남겨졌나요?","options":["O","X"],"answer":"O","hints":[["첫 번째 문장을 다시 읽어봐요!"],["''혼자 남겨졌어요''라는 표현이 있어요. 찾았나요?"]]},{"question_id":2,"related_sentence":"길동이는 관세음보살님께 누나가 빨리 오게 해달라고 빌고 또 빌었어요.","question":"길동이가 관세음보살님께 빈 것은 무엇인가요?","options":["누나가 빨리 오게 해달라고","밥을 먹게 해달라고","눈이 그치게 해달라고"],"answer":"누나가 빨리 오게 해달라고","hints":[["길동이가 무엇을 빌었는지 글에서 찾아봐요!"],["''누나가 빨리 오게''라는 표현이 있어요. 거의 다 왔어요!"]]},{"question_id":3,"related_sentence":"추운 밤이 지나고 아침이 되었지만 누나는 여전히 오지 않았어요.","question":"아침이 되었을 때 누나가 돌아왔나요?","options":["O","X"],"answer":"X","hints":[["마지막 문장을 읽어봐요!"],["''여전히 오지 않았어요''라는 표현이 있어요. 찾았나요?"]]}]},{"cycle_number":3,"cycle_type":"diagram_order","diagram_type":"sequence","boxes":[{"id":1,"is_blank":true},{"id":2,"is_blank":false,"content":"날이 어두워지자 점점 불안해졌다"},{"id":3,"is_blank":true}],"questions":[{"question_id":1,"target_box":1,"related_sentence":"처음에는 누나가 곧 돌아올 거라 생각해서 무섭지 않았어요.","question":"처음에 길동이의 마음은 어땠나요?","options":["누나가 올 거라 생각해서 무섭지 않았다","너무 무서워서 울었다","누나를 찾아 밖으로 나갔다"],"answer":"누나가 올 거라 생각해서 무섭지 않았다","hints":[["처음에 길동이가 어떤 마음이었는지 글에서 찾아봐요!"],["''무섭지 않았어요''라는 표현이 있어요. 할 수 있어요!"]]},{"question_id":2,"target_box":3,"related_sentence":"길동이는 관세음보살님께 누나가 빨리 오게 해달라고 빌고 또 빌었어요.","question":"불안해진 길동이가 한 일은 무엇인가요?","options":["관세음보살님께 빌고 또 빌었다","암자 밖으로 뛰어나갔다","그냥 잠을 잤다"],"answer":"관세음보살님께 빌고 또 빌었다","hints":[["불안해진 길동이가 어떻게 했는지 찾아봐요!"],["''빌고 또 빌었어요''라는 표현이 있어요. 거의 다 왔어요!"]]},{"question_id":3,"target_box":2,"related_sentence":"하지만 날이 어두워지고 누나가 오지 않자 길동이는 점점 불안해졌어요.","question":"길동이가 불안해진 까닭은 무엇인가요?","options":["날이 어두워지고 누나가 오지 않아서","암자가 너무 추워서","밥이 없어서"],"answer":"날이 어두워지고 누나가 오지 않아서","hints":[["길동이가 왜 불안해졌는지 글에서 찾아봐요!"],["''날이 어두워지고 누나가 오지 않자''라는 표현이 있어요. 찾았나요?"]]}]},{"cycle_number":4,"cycle_type":"inference","questions":[{"question_id":1,"scene_image":"scene_gildong_alone.png","related_sentence":"하지만 날이 어두워지고 누나가 오지 않자 길동이는 점점 불안해졌어요.","question":"날이 어두워지는데 누나가 오지 않을 때 길동이는 어떤 기분이었을까요?","options":["무섭고 외로웠을 것이다","신나고 즐거웠을 것이다","배가 고팠을 것이다"],"answer":"무섭고 외로웠을 것이다","hints":[["혼자 어두운 곳에 있으면 어떤 기분일까요?"],["어두운 곳에 혼자 있으면 무섭고 외롭잖아요. 잘하고 있어요!"]]},{"question_id":2,"scene_image":"scene_gildong_pray.png","related_sentence":"길동이는 관세음보살님께 누나가 빨리 오게 해달라고 빌고 또 빌었어요.","question":"길동이가 빌고 또 빈 까닭은 무엇일까요?","options":["누나가 너무 보고 싶고 걱정됐기 때문이다","관세음보살님이 좋아서","기도하는 게 재미있어서"],"answer":"누나가 너무 보고 싶고 걱정됐기 때문이다","hints":[["길동이가 가장 원하는 게 뭔지 생각해봐요!"],["혼자 남겨진 길동이에게 가장 필요한 건 누나잖아요. 거의 다 왔어요!"]]},{"question_id":3,"scene_image":"scene_gildong_morning.png","related_sentence":"추운 밤이 지나고 아침이 되었지만 누나는 여전히 오지 않았어요.","question":"아침이 되었는데도 누나가 오지 않았을 때 길동이는 어떤 기분이었을까요?","options":["더 슬프고 힘들었을 것이다","아침이 되어서 기뻤을 것이다","누나 생각이 없었을 것이다"],"answer":"더 슬프고 힘들었을 것이다","hints":[["기다렸는데도 누나가 오지 않으면 어떤 기분일까요?"],["기다려도 오지 않으면 더 슬프고 힘들잖아요. 할 수 있어요!"]]}]},{"cycle_number":5,"cycle_type":"summary_fill","summary_template":"길동이는 산속 암자에 [BLANK_1] 남겨졌어요. 날이 어두워지고 누나가 오지 않자 길동이는 [BLANK_2] 관세음보살님께 누나가 빨리 오게 해달라고 빌었어요.","questions":[{"question_id":1,"target_blank":"BLANK_1","question":"길동이는 어떻게 남겨졌나요?","options":["혼자","친구와 함께","누나와 함께"],"answer":"혼자","hints":[["길동이가 암자에 누구와 있었는지 떠올려봐요!"],["''혼자 남겨졌어요''라는 표현이 힌트예요. 거의 다 왔어요!"]]},{"question_id":2,"target_blank":"BLANK_2","question":"길동이는 어떤 마음이 들었나요?","options":["점점 불안해져서","신이 나서","배가 고파서"],"answer":"점점 불안해져서","hints":[["누나가 오지 않자 길동이의 마음이 어떻게 됐는지 떠올려봐요!"],["''불안''이 들어간 표현이에요. 잘하고 있어요!"]]},{"question_id":3,"target_blank":null,"question":"이 글에서 길동이의 마음 변화로 알맞은 것은 무엇인가요?","options":["무섭지 않음 → 점점 불안해짐","불안함 → 점점 신남","슬픔 → 점점 기쁨"],"answer":"무섭지 않음 → 점점 불안해짐","hints":[["처음 길동이 마음과 나중 길동이 마음을 비교해봐요!"],["처음엔 괜찮았는데 나중엔 어떻게 됐나요? 거의 다 왔어요!"]]}]}]}'::jsonb)
INSERT INTO korean_step (grade, step_number, step_title, concept, content_json) VALUES
(4, 3, '환경을 지키는 초록 슈퍼맨', '글 요약, 의견 파악', '{"subject":"korean","step_id":"grade4_step3","step_title":"환경을 지키는 초록 슈퍼맨","grade":4,"unit_concept":["글 요약","의견 파악"],"passage":{"title":"환경을 지키는 초록 슈퍼맨","text":"우리 주변의 환경이 점점 오염되고 있어요. 공장에서 나오는 연기와 쓰레기 때문에 공기와 강물이 더러워지고 있어요. 환경이 오염되면 동물과 식물도 살기 힘들어지고, 우리 건강도 나빠져요. 그래서 우리 모두가 작은 것부터 실천해야 해요. 분리수거를 잘 하고, 대중교통을 이용하면 환경을 지킬 수 있어요.","image":"passage_grade4_step3.png"},"cycles":[{"cycle_number":1,"cycle_type":"word_card","slides":[{"word":"오염","image":"word_oyeom.png","description":"공기나 물이 더럽고 나쁘게 변하는 것이에요!","confirm_button_text":"이해했어!"},{"word":"분리수거","image":"word_bullisugeo.png","description":"쓰레기를 종류별로 나눠서 버리는 것이에요!","confirm_button_text":"이해했어!"},{"word":"대중교통","image":"word_daejunggyotong.png","description":"버스나 지하철처럼 많은 사람이 함께 타는 교통수단이에요!","confirm_button_text":"시작해볼게!"}]},{"cycle_number":2,"cycle_type":"fact_check","questions":[{"question_id":1,"related_sentence":"공장에서 나오는 연기와 쓰레기 때문에 공기와 강물이 더러워지고 있어요.","question":"환경이 오염되는 까닭 중 하나는 공장 연기와 쓰레기인가요?","options":["O","X"],"answer":"O","hints":[["두 번째 문장을 다시 읽어봐요!"],["''공장에서 나오는 연기와 쓰레기 때문에''라는 표현이 있어요. 찾았나요?"]]},{"question_id":2,"related_sentence":"환경이 오염되면 동물과 식물도 살기 힘들어지고, 우리 건강도 나빠져요.","question":"환경이 오염되면 우리 건강은 어떻게 되나요?","options":["나빠진다","좋아진다","달라지지 않는다"],"answer":"나빠진다","hints":[["환경 오염이 우리 건강에 어떤 영향을 주는지 글에서 찾아봐요!"],["''우리 건강도 나빠져요''라는 표현이 있어요. 거의 다 왔어요!"]]},{"question_id":3,"related_sentence":"분리수거를 잘 하고, 대중교통을 이용하면 환경을 지킬 수 있어요.","question":"환경을 지키는 방법으로 글에서 말한 것은 무엇인가요?","options":["분리수거와 대중교통 이용","공장 문 닫기","나무 베기"],"answer":"분리수거와 대중교통 이용","hints":[["글의 마지막 문장에서 환경을 지키는 방법을 찾아봐요!"],["''분리수거''와 ''대중교통''이라는 낱말이 있어요. 찾았나요?"]]}]},{"cycle_number":3,"cycle_type":"diagram_order","diagram_type":"cause_effect","boxes":[{"id":1,"is_blank":false,"content":"공장 연기와 쓰레기로 환경이 오염되고 있다"},{"id":2,"is_blank":true},{"id":3,"is_blank":true},{"id":4,"is_blank":true}],"questions":[{"question_id":1,"target_box":2,"related_sentence":"환경이 오염되면 동물과 식물도 살기 힘들어지고, 우리 건강도 나빠져요.","question":"환경이 오염되면 어떤 일이 생기나요?","options":["동물·식물이 살기 힘들어지고 건강도 나빠진다","공기가 맑아진다","강물이 깨끗해진다"],"answer":"동물·식물이 살기 힘들어지고 건강도 나빠진다","hints":[["환경 오염의 결과를 글에서 찾아봐요!"],["''살기 힘들어지고, 건강도 나빠져요''라는 표현이 있어요. 거의 다 왔어요!"]]},{"question_id":2,"target_box":3,"related_sentence":"그래서 우리 모두가 작은 것부터 실천해야 해요.","question":"환경을 지키기 위해 우리는 어떻게 해야 하나요?","options":["작은 것부터 실천해야 한다","아무것도 하지 않아도 된다","전문가만 해결하면 된다"],"answer":"작은 것부터 실천해야 한다","hints":[["우리가 환경을 위해 무엇을 해야 한다고 했는지 찾아봐요!"],["''작은 것부터 실천해야 해요''라는 표현이 있어요. 할 수 있어요!"]]},{"question_id":3,"target_box":4,"related_sentence":"분리수거를 잘 하고, 대중교통을 이용하면 환경을 지킬 수 있어요.","question":"우리가 실천하면 어떤 결과가 생기나요?","options":["환경을 지킬 수 있다","환경이 더 나빠진다","아무것도 달라지지 않는다"],"answer":"환경을 지킬 수 있다","hints":[["분리수거와 대중교통 이용을 하면 어떻게 된다고 했는지 찾아봐요!"],["''환경을 지킬 수 있어요''라는 표현이 있어요. 찾았나요?"]]}]},{"cycle_number":4,"cycle_type":"inference","questions":[{"question_id":1,"scene_image":"scene_pollution.png","related_sentence":"우리 주변의 환경이 점점 오염되고 있어요.","question":"환경이 오염되는 걸 보면 어떤 기분이 드나요?","options":["걱정되고 안타깝다","신나고 즐겁다","아무 느낌이 없다"],"answer":"걱정되고 안타깝다","hints":[["소중한 환경이 더러워지는 걸 보면 어떤 기분일까요?"],["좋아하는 것이 망가지면 걱정되고 안타깝잖아요. 잘하고 있어요!"]]},{"question_id":2,"scene_image":"scene_recycle.png","related_sentence":"그래서 우리 모두가 작은 것부터 실천해야 해요.","question":"이 글을 쓴 사람은 우리에게 어떻게 하길 바라고 있나요?","options":["환경을 지키기 위해 함께 실천하길 바란다","환경 문제는 어른만 해결하길 바란다","환경 오염은 괜찮다고 생각한다"],"answer":"환경을 지키기 위해 함께 실천하길 바란다","hints":[["글쓴이가 우리에게 무엇을 바라고 있는지 생각해봐요!"],["''우리 모두가 실천해야 해요''라고 했어요. 거의 다 왔어요!"]]},{"question_id":3,"scene_image":"scene_green_earth.png","related_sentence":"분리수거를 잘 하고, 대중교통을 이용하면 환경을 지킬 수 있어요.","question":"내가 분리수거를 열심히 한다면 어떤 기분이 들까요?","options":["환경을 지켜서 뿌듯할 것이다","힘들고 하기 싫을 것이다","아무 기분도 안 들 것이다"],"answer":"환경을 지켜서 뿌듯할 것이다","hints":[["좋은 일을 하면 어떤 기분이 드나요?"],["환경을 위해 좋은 일을 하면 뿌듯하잖아요. 할 수 있어요!"]]}]},{"cycle_number":5,"cycle_type":"summary_fill","summary_template":"환경이 [BLANK_1] 동물과 식물도 살기 힘들고 건강도 나빠져요. 그래서 우리 모두가 분리수거와 대중교통 이용 같은 [BLANK_2] 환경을 지킬 수 있어요.","questions":[{"question_id":1,"target_blank":"BLANK_1","question":"환경이 어떻게 되고 있나요?","options":["점점 오염되면","점점 깨끗해지면","그대로이면"],"answer":"점점 오염되면","hints":[["환경이 지금 어떻게 되고 있는지 떠올려봐요!"],["''오염''이 들어간 표현이에요. 거의 다 왔어요!"]]},{"question_id":2,"target_blank":"BLANK_2","question":"어떻게 하면 환경을 지킬 수 있나요?","options":["작은 것부터 실천하면","아무것도 하지 않으면","전문가에게 맡기면"],"answer":"작은 것부터 실천하면","hints":[["우리가 환경을 위해 어떻게 해야 한다고 했는지 떠올려봐요!"],["''작은 것부터 실천''이라는 표현이 힌트예요. 잘하고 있어요!"]]},{"question_id":3,"target_blank":null,"question":"이 글에서 글쓴이가 말하고 싶은 것은 무엇인가요?","options":["환경을 지키기 위해 우리 모두 함께 실천해야 한다","환경 오염은 어쩔 수 없는 일이다","공장을 모두 없애야 한다"],"answer":"환경을 지키기 위해 우리 모두 함께 실천해야 한다","hints":[["글쓴이가 이 글에서 가장 하고 싶은 말이 무엇인지 생각해봐요!"],["''우리 모두가 실천해야 해요''라는 표현이 중심 생각이에요. 찾았나요?"]]}]}]}'::jsonb)
INSERT INTO korean_step (grade, step_number, step_title, concept, content_json) VALUES
(5, 1, '지우개를 같이 쓰면 안 될까', '의견 조정, 공감 대화, 이유 말하기', '{"subject":"korean","step_id":"grade5_step1","step_title":"지우개를 같이 쓰면 안 될까","grade":5,"unit_concept":["의견 조정","공감 대화","이유 말하기"],"passage":{"title":"지우개를 같이 쓰면 안 될까","text":"민수는 미술 시간에 지우개가 없어서 지우에게 빌려 달라고 했어요. 지우는 새 지우개라서 더러워질까 봐 걱정했어요. 민수는 꼭 필요하다며 잠깐만 쓰고 돌려주겠다고 말했어요. 지우는 민수의 마음을 생각해 보고, 조심히 쓰기로 약속하면 빌려주겠다고 했어요. 두 사람은 서로의 생각을 말하고 방법을 정했어요.","image":"passage_grade5_step1.png"},"cycles":[{"cycle_number":1,"cycle_type":"word_card","slides":[{"word":"의견","image":"word_uigyeon.png","description":"어떤 일에 대한 내 생각이에요!","confirm_button_text":"이해했어!"},{"word":"조정","image":"word_jojeong.png","description":"서로 다른 생각을 맞춰 가는 것이에요!","confirm_button_text":"이해했어!"},{"word":"약속","image":"word_yaksok.png","description":"앞으로 어떻게 하겠다고 정하는 것이에요!","confirm_button_text":"시작해볼게!"}]},{"cycle_number":2,"cycle_type":"fact_check","questions":[{"question_id":1,"related_sentence":"민수는 미술 시간에 지우개가 없어서 지우에게 빌려 달라고 했어요.","question":"민수는 지우개가 없어서 지우에게 빌려 달라고 했나요?","options":["O","X"],"answer":"O","hints":[["첫 번째 문장을 다시 읽어봐요!"],["''지우개가 없어서''라는 표현이 있어요. 찾았나요?"]]},{"question_id":2,"related_sentence":"지우는 새 지우개라서 더러워질까 봐 걱정했어요.","question":"지우가 걱정한 까닭은 무엇인가요?","options":["새 지우개가 더러워질까 봐","지우개를 잃어버려서","미술 시간이 싫어서"],"answer":"새 지우개가 더러워질까 봐","hints":[["지우가 왜 걱정했는지 글에서 찾아봐요!"],["''더러워질까 봐 걱정했어요''라는 표현이 있어요. 거의 다 왔어요!"]]},{"question_id":3,"related_sentence":"두 사람은 서로의 생각을 말하고 방법을 정했어요.","question":"민수와 지우는 어떻게 문제를 해결했나요?","options":["서로의 생각을 말하고 방법을 정했다","아무 말도 하지 않았다","서로 화를 냈다"],"answer":"서로의 생각을 말하고 방법을 정했다","hints":[["마지막 문장을 읽어봐요!"],["''서로의 생각을 말하고''라는 표현이 있어요. 잘하고 있어요!"]]}]},{"cycle_number":3,"cycle_type":"diagram_order","diagram_type":"sequence","boxes":[{"id":1,"is_blank":false,"content":"민수가 지우개를 빌려 달라고 했다"},{"id":2,"is_blank":true},{"id":3,"is_blank":true},{"id":4,"is_blank":true}],"questions":[{"question_id":1,"target_box":2,"related_sentence":"지우는 새 지우개라서 더러워질까 봐 걱정했어요.","question":"민수가 지우개를 빌려 달라고 하자 지우는 어떻게 생각했나요?","options":["새 지우개가 더러워질까 봐 걱정했다","바로 지우개를 버렸다","민수 말을 듣지 않았다"],"answer":"새 지우개가 더러워질까 봐 걱정했다","hints":[["지우의 마음을 글에서 찾아봐요!"],["''걱정했어요''라는 표현이 힌트예요. 할 수 있어요!"]]},{"question_id":2,"target_box":3,"related_sentence":"민수는 꼭 필요하다며 잠깐만 쓰고 돌려주겠다고 말했어요.","question":"민수는 지우에게 어떻게 말했나요?","options":["잠깐만 쓰고 돌려주겠다고 말했다","계속 가지고 있겠다고 말했다","아무 말도 하지 않았다"],"answer":"잠깐만 쓰고 돌려주겠다고 말했다","hints":[["민수가 지우에게 한 말을 찾아봐요!"],["''잠깐만 쓰고 돌려주겠다고''라는 표현이 있어요. 거의 다 왔어요!"]]},{"question_id":3,"target_box":4,"related_sentence":"지우는 민수의 마음을 생각해 보고, 조심히 쓰기로 약속하면 빌려주겠다고 했어요.","question":"지우는 어떤 조건으로 지우개를 빌려주기로 했나요?","options":["조심히 쓰기로 약속하면","새 지우개를 사 오면","미술 시간이 끝나면"],"answer":"조심히 쓰기로 약속하면","hints":[["지우가 어떤 약속을 말했는지 찾아봐요!"],["''조심히 쓰기로 약속하면''이라는 표현이 있어요. 찾았나요?"]]}]},{"cycle_number":4,"cycle_type":"inference","questions":[{"question_id":1,"scene_image":"scene_eraser_borrow.png","related_sentence":"민수는 미술 시간에 지우개가 없어서 지우에게 빌려 달라고 했어요.","question":"지우개가 꼭 필요한 민수는 어떤 기분이었을까요?","options":["난처하고 급했을 것이다","신나고 즐거웠을 것이다","아무렇지 않았을 것이다"],"answer":"난처하고 급했을 것이다","hints":[["필요한 물건이 없으면 어떤 기분일까요?"],["수업 시간에 필요한 물건이 없으면 난처하고 급할 수 있어요. 잘하고 있어요!"]]},{"question_id":2,"scene_image":"scene_eraser_worry.png","related_sentence":"지우는 새 지우개라서 더러워질까 봐 걱정했어요.","question":"지우가 바로 빌려주지 못한 까닭은 무엇일까요?","options":["새 지우개를 아끼는 마음이 있었기 때문이다","민수를 싫어했기 때문이다","지우개가 필요 없었기 때문이다"],"answer":"새 지우개를 아끼는 마음이 있었기 때문이다","hints":[["지우가 무엇을 걱정했는지 떠올려봐요!"],["새 물건을 아끼면 더러워질까 걱정될 수 있어요. 거의 다 왔어요!"]]},{"question_id":3,"scene_image":"scene_eraser_talk.png","related_sentence":"두 사람은 서로의 생각을 말하고 방법을 정했어요.","question":"민수와 지우가 서로의 생각을 말한 것은 왜 좋았을까요?","options":["서로 마음을 알고 방법을 정할 수 있어서","누가 더 센지 알 수 있어서","말을 안 해도 되어서"],"answer":"서로 마음을 알고 방법을 정할 수 있어서","hints":[["생각을 말하면 어떤 점이 좋을까요?"],["서로의 마음을 알면 함께 방법을 찾기 쉬워요. 할 수 있어요!"]]}]},{"cycle_number":5,"cycle_type":"summary_fill","summary_template":"민수는 지우개가 없어서 지우에게 빌려 달라고 했어요. 지우는 새 지우개가 [BLANK_1] 걱정했어요. 두 사람은 서로의 생각을 말하고 [BLANK_2] 문제를 해결했어요.","questions":[{"question_id":1,"target_blank":"BLANK_1","question":"지우는 새 지우개가 어떻게 될까 봐 걱정했나요?","options":["더러워질까 봐","사라질까 봐","커질까 봐"],"answer":"더러워질까 봐","hints":[["지우가 걱정한 이유를 떠올려봐요!"],["''더러워질까 봐''라는 표현이 힌트예요. 거의 다 왔어요!"]]},{"question_id":2,"target_blank":"BLANK_2","question":"두 사람은 어떻게 문제를 해결했나요?","options":["방법을 정해서","싸워서","그냥 피해서"],"answer":"방법을 정해서","hints":[["마지막 문장을 떠올려봐요!"],["서로 생각을 말한 뒤 무엇을 정했나요? 잘하고 있어요!"]]},{"question_id":3,"target_blank":null,"question":"이 글에서 알 수 있는 생각으로 알맞은 것은 무엇인가요?","options":["의견이 다를 때는 서로 생각을 말하고 방법을 정하면 좋다","친구에게는 아무것도 빌려주면 안 된다","걱정되는 마음은 말하지 않아야 한다"],"answer":"의견이 다를 때는 서로 생각을 말하고 방법을 정하면 좋다","hints":[["민수와 지우가 어떻게 해결했는지 생각해봐요!"],["서로 말하고 방법을 정한 점이 중요해요. 찾았나요?"]]}]}]}'::jsonb)
INSERT INTO korean_step (grade, step_number, step_title, concept, content_json) VALUES
(5, 2, 'SNS 댓글 때문에 속상했던 레오', '상대 감정 이해, 공감 대화, 말의 영향', '{"subject":"korean","step_id":"grade5_step2","step_title":"SNS 댓글 때문에 속상했던 레오","grade":5,"unit_concept":["상대 감정 이해","공감 대화","말의 영향"],"passage":{"title":"SNS 댓글 때문에 속상했던 레오","text":"레오는 직접 만든 그림을 SNS에 올렸어요. 그런데 어떤 친구가 그림이 이상하다는 댓글을 남겼어요. 레오는 그 댓글을 보고 속상한 마음이 들었어요. 다음 날 친구는 장난으로 쓴 댓글이었다며 미안하다고 말했어요. 레오는 친구의 사과를 듣고 자신의 마음도 솔직하게 이야기했어요.","image":"passage_grade5_step2.png"},"cycles":[{"cycle_number":1,"cycle_type":"word_card","slides":[{"word":"댓글","image":"word_comment.png","description":"글이나 사진 아래에 남기는 짧은 글이에요!","confirm_button_text":"이해했어!"},{"word":"속상하다","image":"word_soksang.png","description":"마음이 슬프고 서운한 느낌이에요!","confirm_button_text":"이해했어!"},{"word":"사과","image":"word_apology.png","description":"잘못한 일을 미안하다고 말하는 것이에요!","confirm_button_text":"시작해볼게!"}]},{"cycle_number":2,"cycle_type":"fact_check","questions":[{"question_id":1,"related_sentence":"레오는 직접 만든 그림을 SNS에 올렸어요.","question":"레오는 자신이 만든 그림을 SNS에 올렸나요?","options":["O","X"],"answer":"O","hints":[["첫 번째 문장에 답이 숨어 있어 😊"],["레오가 SNS에 무엇을 올렸는지 천천히 찾아보자!"]]},{"question_id":2,"related_sentence":"어떤 친구가 그림이 이상하다는 댓글을 남겼어요.","question":"친구는 어떤 댓글을 남겼나요?","options":["그림이 이상하다고 했다","그림이 멋지다고 했다","아무 댓글도 남기지 않았다"],"answer":"그림이 이상하다고 했다","hints":[["친구가 남긴 말을 다시 읽어보자 🌱"],["''이상하다''라는 말이 보일 거야!"]]},{"question_id":3,"related_sentence":"다음 날 친구는 장난으로 쓴 댓글이었다며 미안하다고 말했어요.","question":"친구는 다음 날 어떻게 했나요?","options":["미안하다고 말했다","다시 놀렸다","아무 말도 하지 않았다"],"answer":"미안하다고 말했다","hints":[["다음 날 친구가 한 행동을 떠올려보자 😊"],["''미안하다''라는 표현이 중요한 힌트야!"]]}]},{"cycle_number":3,"cycle_type":"diagram_order","diagram_type":"sequence","boxes":[{"id":1,"is_blank":false,"content":"레오가 그림을 SNS에 올렸다"},{"id":2,"is_blank":true},{"id":3,"is_blank":true},{"id":4,"is_blank":true}],"questions":[{"question_id":1,"target_box":2,"related_sentence":"어떤 친구가 그림이 이상하다는 댓글을 남겼어요.","question":"그림을 본 친구는 어떻게 했나요?","options":["이상하다는 댓글을 남겼다","그림을 지웠다","아무 말도 하지 않았다"],"answer":"이상하다는 댓글을 남겼다","hints":[["친구가 남긴 행동을 찾아보자 👀"],["댓글 내용 안에 중요한 답이 있어!"]]},{"question_id":2,"target_box":3,"related_sentence":"레오는 그 댓글을 보고 속상한 마음이 들었어요.","question":"댓글을 본 레오의 마음은 어땠나요?","options":["속상했다","신났다","화가 나지 않았다"],"answer":"속상했다","hints":[["레오 마음에 집중해서 읽어보자 😊"],["마음과 관련된 표현이 보일 거야!"]]},{"question_id":3,"target_box":4,"related_sentence":"레오는 친구의 사과를 듣고 자신의 마음도 솔직하게 이야기했어요.","question":"레오는 친구의 사과를 듣고 어떻게 했나요?","options":["자신의 마음을 솔직하게 이야기했다","아무 말도 하지 않았다","친구를 피해 다녔다"],"answer":"자신의 마음을 솔직하게 이야기했다","hints":[["마지막 문장을 천천히 읽어보자 🌱"],["레오가 자신의 마음을 어떻게 했는지 찾아보면 돼!"]]}]},{"cycle_number":4,"cycle_type":"inference","questions":[{"question_id":1,"scene_image":"scene_sns_comment.png","related_sentence":"레오는 그 댓글을 보고 속상한 마음이 들었어요.","question":"레오는 왜 더 속상했을까요?","options":["열심히 만든 그림이었기 때문이다","그림을 싫어해서","SNS가 재미없어서"],"answer":"열심히 만든 그림이었기 때문이다","hints":[["내가 열심히 한 일을 누가 안 좋게 말하면 어떤 기분일까? 😊"],["레오가 그림을 직접 만들었다는 점을 떠올려보자!"]]},{"question_id":2,"scene_image":"scene_friend_apology.png","related_sentence":"친구는 장난으로 쓴 댓글이었다며 미안하다고 말했어요.","question":"친구가 미안하다고 말한 이유는 무엇일까요?","options":["레오가 속상해한 걸 알게 되었기 때문이다","댓글 쓰기가 귀찮아졌기 때문이다","SNS를 그만하고 싶었기 때문이다"],"answer":"레오가 속상해한 걸 알게 되었기 때문이다","hints":[["친구는 왜 사과했을지 같이 생각해보자 🌱"],["상대 마음을 알게 되면 미안한 마음이 들 수 있어!"]]},{"question_id":3,"scene_image":"scene_talk_together.png","related_sentence":"레오는 친구의 사과를 듣고 자신의 마음도 솔직하게 이야기했어요.","question":"레오가 자신의 마음을 솔직하게 말한 것은 왜 좋았을까요?","options":["서로의 마음을 이해할 수 있어서","더 크게 싸울 수 있어서","아무 생각 없이 말해서"],"answer":"서로의 마음을 이해할 수 있어서","hints":[["마음을 이야기하면 어떤 점이 좋을까? 😊"],["서로의 마음을 알면 오해를 줄일 수 있어!"]]}]},{"cycle_number":5,"cycle_type":"summary_fill","summary_template":"레오는 직접 만든 그림을 SNS에 올렸어요. 하지만 친구의 댓글을 보고 [BLANK_1] 다음 날 친구는 미안하다고 사과했고, 레오는 자신의 마음을 [BLANK_2]","questions":[{"question_id":1,"target_blank":"BLANK_1","question":"레오는 댓글을 보고 어떤 마음이 들었나요?","options":["속상한 마음이 들었다","신나는 마음이 들었다","아무 마음도 들지 않았다"],"answer":"속상한 마음이 들었다","hints":[["레오의 마음을 다시 떠올려보자 🌱"],["마음과 관련된 표현이 글 안에 있어!"]]},{"question_id":2,"target_blank":"BLANK_2","question":"레오는 자신의 마음을 어떻게 했나요?","options":["솔직하게 이야기했다","숨겼다","잊어버렸다"],"answer":"솔직하게 이야기했다","hints":[["마지막 문장을 보면 도움이 될 거야 😊"],["레오가 자신의 마음을 어떻게 표현했는지 찾아보자!"]]},{"question_id":3,"target_blank":null,"question":"이 글에서 알 수 있는 생각으로 알맞은 것은 무엇인가요?","options":["말은 다른 사람의 마음에 영향을 줄 수 있다","장난은 언제나 괜찮다","속상한 마음은 말하면 안 된다"],"answer":"말은 다른 사람의 마음에 영향을 줄 수 있다","hints":[["이 글에서 말과 마음이 어떻게 연결되는지 생각해보자 🌱"],["친구의 댓글 때문에 레오 마음이 어떻게 되었는지 떠올려보면 좋아!"]]}]}]}'::jsonb)
INSERT INTO korean_step (grade, step_number, step_title, concept, content_json) VALUES
(5, 3, '텀블러와 함께한 하루', '주장과 근거, 실천 방법 찾기, 중요 내용 요약', '{"subject":"korean","step_id":"grade5_step3","step_title":"텀블러와 함께한 하루","grade":5,"unit_concept":["주장과 근거","실천 방법 찾기","중요 내용 요약"],"passage":{"title":"텀블러와 함께한 하루","text":"유나는 학교에 갈 때 텀블러에 물을 담아 갔어요. 예전에는 음료를 마실 때마다 일회용 컵을 자주 사용했어요. 하지만 버려지는 컵이 많아지면 환경이 더러워질 수 있다는 이야기를 듣게 되었어요. 그래서 유나는 텀블러를 사용하기 시작했어요. 유나는 작은 실천이지만 환경을 지키는 데 도움이 된다고 생각했어요.","image":"passage_grade5_step3.png"},"cycles":[{"cycle_number":1,"cycle_type":"word_card","slides":[{"word":"텀블러","image":"word_tumbler.png","description":"여러 번 사용할 수 있는 물병이나 컵이에요!","confirm_button_text":"이해했어!"},{"word":"일회용","image":"word_disposable.png","description":"한 번 쓰고 버리는 것이에요!","confirm_button_text":"이해했어!"},{"word":"실천","image":"word_practice.png","description":"생각한 것을 직접 행동으로 해 보는 것이에요!","confirm_button_text":"시작해볼게!"}]},{"cycle_number":2,"cycle_type":"fact_check","questions":[{"question_id":1,"related_sentence":"유나는 학교에 갈 때 텀블러에 물을 담아 갔어요.","question":"유나는 학교에 갈 때 텀블러를 가져갔나요?","options":["O","X"],"answer":"O","hints":[["첫 문장에 답이 숨어 있어 😊"],["유나가 무엇을 가져갔는지 천천히 찾아보자!"]]},{"question_id":2,"related_sentence":"예전에는 음료를 마실 때마다 일회용 컵을 자주 사용했어요.","question":"유나는 예전에 무엇을 자주 사용했나요?","options":["일회용 컵","텀블러","유리병"],"answer":"일회용 컵","hints":[["예전 유나의 행동을 떠올려보자 🌱"],["''자주 사용했어요'' 앞에 중요한 말이 있어!"]]},{"question_id":3,"related_sentence":"유나는 작은 실천이지만 환경을 지키는 데 도움이 된다고 생각했어요.","question":"유나는 텀블러 사용이 무엇에 도움이 된다고 생각했나요?","options":["환경을 지키는 데","숙제를 줄이는 데","친구를 놀라게 하는 데"],"answer":"환경을 지키는 데","hints":[["유나가 왜 텀블러를 사용했는지 생각해보자 😊"],["마지막 문장에 중요한 답이 있어!"]]}]},{"cycle_number":3,"cycle_type":"diagram_order","diagram_type":"cause_effect","boxes":[{"id":1,"is_blank":false,"content":"일회용 컵이 많이 버려지고 있다"},{"id":2,"is_blank":true},{"id":3,"is_blank":true},{"id":4,"is_blank":true}],"questions":[{"question_id":1,"target_box":2,"related_sentence":"버려지는 컵이 많아지면 환경이 더러워질 수 있다는 이야기를 듣게 되었어요.","question":"일회용 컵이 많아지면 어떤 일이 생길 수 있나요?","options":["환경이 더러워질 수 있다","공기가 더 깨끗해진다","컵이 사라진다"],"answer":"환경이 더러워질 수 있다","hints":[["컵이 많이 버려지면 환경이 어떻게 될지 생각해보자 🌱"],["''환경이 더러워질 수 있다''는 표현이 보여!"]]},{"question_id":2,"target_box":3,"related_sentence":"그래서 유나는 텀블러를 사용하기 시작했어요.","question":"유나는 환경 이야기를 듣고 어떻게 했나요?","options":["텀블러를 사용하기 시작했다","컵을 더 많이 버렸다","아무것도 하지 않았다"],"answer":"텀블러를 사용하기 시작했다","hints":[["유나가 시작한 행동을 찾아보자 😊"],["''사용하기 시작했어요''라는 표현이 힌트야!"]]},{"question_id":3,"target_box":4,"related_sentence":"유나는 작은 실천이지만 환경을 지키는 데 도움이 된다고 생각했어요.","question":"유나는 자신의 행동이 어떤 도움이 된다고 생각했나요?","options":["환경을 지키는 데 도움이 된다고 생각했다","환경과 상관없다고 생각했다","불편하기만 하다고 생각했다"],"answer":"환경을 지키는 데 도움이 된다고 생각했다","hints":[["유나의 생각을 천천히 읽어보자 👀"],["''도움이 된다''는 표현 근처를 보면 좋아!"]]}]},{"cycle_number":4,"cycle_type":"inference","questions":[{"question_id":1,"scene_image":"scene_tumbler_school.png","related_sentence":"유나는 학교에 갈 때 텀블러에 물을 담아 갔어요.","question":"유나는 왜 텀블러를 챙겨 가려고 했을까요?","options":["환경을 위해 실천해 보려고","친구에게 자랑하려고","가방을 무겁게 하려고"],"answer":"환경을 위해 실천해 보려고","hints":[["유나가 중요하게 생각한 것을 떠올려보자 😊"],["환경을 위한 행동이었다는 점이 힌트야!"]]},{"question_id":2,"scene_image":"scene_disposable_cups.png","related_sentence":"버려지는 컵이 많아지면 환경이 더러워질 수 있다는 이야기를 듣게 되었어요.","question":"유나는 이 이야기를 듣고 어떤 마음이 들었을까요?","options":["환경을 지켜야겠다고 생각했을 것이다","아무 상관없다고 생각했을 것이다","컵을 더 쓰고 싶어졌을 것이다"],"answer":"환경을 지켜야겠다고 생각했을 것이다","hints":[["환경 이야기를 들은 유나 마음을 생각해보자 🌱"],["환경이 더러워진다는 말을 들으면 어떤 생각이 들까?"]]},{"question_id":3,"scene_image":"scene_green_action.png","related_sentence":"유나는 작은 실천이지만 환경을 지키는 데 도움이 된다고 생각했어요.","question":"작은 실천을 계속하면 어떤 점이 좋을까요?","options":["환경을 지키는 데 도움이 될 수 있다","아무 변화가 없다","환경이 더 나빠질 수 있다"],"answer":"환경을 지키는 데 도움이 될 수 있다","hints":[["작은 행동도 모이면 큰 도움이 될 수 있어 😊"],["유나가 왜 텀블러를 계속 사용하려 했는지 떠올려보자!"]]}]},{"cycle_number":5,"cycle_type":"summary_fill","summary_template":"유나는 예전에 [BLANK_1] 자주 사용했어요. 하지만 환경을 생각하며 텀블러를 사용하기 시작했어요. 유나는 작은 실천도 [BLANK_2] 도움이 된다고 생각했어요.","questions":[{"question_id":1,"target_blank":"BLANK_1","question":"유나는 예전에 무엇을 자주 사용했나요?","options":["일회용 컵","텀블러","도시락통"],"answer":"일회용 컵","hints":[["예전 유나의 모습을 떠올려보자 🌱"],["한 번 쓰고 버리는 컵이 힌트야!"]]},{"question_id":2,"target_blank":"BLANK_2","question":"작은 실천은 어디에 도움이 된다고 했나요?","options":["환경을 지키는 데","숙제를 줄이는 데","잠을 많이 자는 데"],"answer":"환경을 지키는 데","hints":[["유나가 중요하게 생각한 것을 찾아보자 😊"],["마지막 문장을 보면 도움이 될 거야!"]]},{"question_id":3,"target_blank":null,"question":"이 글에서 글쓴이가 말하고 싶은 생각은 무엇인가요?","options":["작은 실천도 환경을 지키는 데 도움이 될 수 있다","텀블러는 무조건 새것만 써야 한다","환경 문제는 나와 상관없다"],"answer":"작은 실천도 환경을 지키는 데 도움이 될 수 있다","hints":[["글 전체에서 가장 중요하게 말하는 생각을 찾아보자 🌱"],["유나가 왜 텀블러를 사용했는지 떠올려보면 좋아!"]]}]}]}'::jsonb)
INSERT INTO korean_step (grade, step_number, step_title, concept, content_json) VALUES
(6, 1, '영상 제목을 믿어도 될까?', '매체 비판, 내용 타당성 판단, 이유 찾기', '{"subject":"korean","step_id":"grade6_step1","step_title":"영상 제목을 믿어도 될까?","grade":6,"unit_concept":["매체 비판","내용 타당성 판단","이유 찾기"],"passage":{"title":"영상 제목을 믿어도 될까?","text":"준호는 인터넷에서 ''하루 만에 키가 10cm 커지는 방법!''이라는 영상을 봤어요. 준호는 정말 가능한 이야기인지 궁금했어요. 영상을 끝까지 본 뒤 준호는 정확한 설명이나 근거가 부족하다고 느꼈어요. 그래서 준호는 바로 믿지 않고 부모님과 함께 다시 찾아보기로 했어요. 준호는 인터넷 정보를 볼 때 한 번 더 확인하는 것이 중요하다고 생각했어요.","image":"passage_grade6_step1.png"},"cycles":[{"cycle_number":1,"cycle_type":"word_card","slides":[{"word":"근거","image":"word_geongeo.png","description":"왜 그렇게 생각하는지 알려 주는 이유나 자료예요!","confirm_button_text":"이해했어!"},{"word":"확인","image":"word_hwagin.png","description":"맞는지 다시 살펴보는 것이에요!","confirm_button_text":"이해했어!"},{"word":"정보","image":"word_jeongbo.png","description":"알려 주는 내용이나 소식이에요!","confirm_button_text":"시작해볼게!"}]},{"cycle_number":2,"cycle_type":"fact_check","questions":[{"question_id":1,"related_sentence":"준호는 인터넷에서 ''하루 만에 키가 10cm 커지는 방법!''이라는 영상을 봤어요.","question":"준호는 인터넷에서 키가 커지는 방법에 대한 영상을 봤나요?","options":["O","X"],"answer":"O","hints":[["첫 문장을 천천히 읽어보자 😊"],["준호가 어떤 영상을 봤는지 제목 속에 답이 있어!"]]},{"question_id":2,"related_sentence":"준호는 정확한 설명이나 근거가 부족하다고 느꼈어요.","question":"준호는 영상을 보고 무엇이 부족하다고 느꼈나요?","options":["정확한 설명과 근거","재미있는 음악","영상 길이"],"answer":"정확한 설명과 근거","hints":[["준호가 부족하다고 느낀 것을 찾아보자 🌱"],["''설명''과 함께 나온 중요한 낱말이 있어!"]]},{"question_id":3,"related_sentence":"그래서 준호는 바로 믿지 않고 부모님과 함께 다시 찾아보기로 했어요.","question":"준호는 어떻게 하기로 했나요?","options":["다시 찾아보기로 했다","친구들에게 바로 알려 주었다","영상을 바로 믿었다"],"answer":"다시 찾아보기로 했다","hints":[["준호가 마지막에 어떤 행동을 했는지 떠올려보자 😊"],["''다시 찾아보기로 했어요''라는 표현이 보여!"]]}]},{"cycle_number":3,"cycle_type":"diagram_order","diagram_type":"sequence","boxes":[{"id":1,"is_blank":false,"content":"준호가 인터넷 영상을 보았다"},{"id":2,"is_blank":true},{"id":3,"is_blank":true},{"id":4,"is_blank":true}],"questions":[{"question_id":1,"target_box":2,"related_sentence":"준호는 정말 가능한 이야기인지 궁금했어요.","question":"준호는 영상을 보고 어떤 생각이 들었나요?","options":["정말 가능한 이야기인지 궁금했다","무조건 맞다고 생각했다","바로 따라 해 보기로 했다"],"answer":"정말 가능한 이야기인지 궁금했다","hints":[["준호 마음속 생각을 떠올려보자 👀"],["''궁금했어요''라는 표현 근처를 보면 좋아!"]]},{"question_id":2,"target_box":3,"related_sentence":"준호는 정확한 설명이나 근거가 부족하다고 느꼈어요.","question":"준호는 영상을 끝까지 본 뒤 어떻게 느꼈나요?","options":["설명과 근거가 부족하다고 느꼈다","모든 내용이 완벽하다고 느꼈다","영상을 이해하지 못했다"],"answer":"설명과 근거가 부족하다고 느꼈다","hints":[["영상을 다 본 뒤 준호 생각이 어떻게 바뀌었는지 보자 🌱"],["''부족하다''라는 표현이 중요한 힌트야!"]]},{"question_id":3,"target_box":4,"related_sentence":"그래서 준호는 바로 믿지 않고 부모님과 함께 다시 찾아보기로 했어요.","question":"준호는 마지막에 어떤 행동을 했나요?","options":["부모님과 함께 다시 찾아보기로 했다","영상을 친구들에게 퍼뜨렸다","바로 따라 해 보았다"],"answer":"부모님과 함께 다시 찾아보기로 했다","hints":[["준호가 선택한 행동을 찾아보자 😊"],["혼자 바로 믿지 않았다는 점이 중요해!"]]}]},{"cycle_number":4,"cycle_type":"inference","questions":[{"question_id":1,"scene_image":"scene_video_title.png","related_sentence":"준호는 정말 가능한 이야기인지 궁금했어요.","question":"준호는 왜 바로 믿지 않았을까요?","options":["정말 가능한 이야기인지 확인하고 싶었기 때문이다","영상 보는 것이 싫었기 때문이다","인터넷을 사용하지 않기 때문이다"],"answer":"정말 가능한 이야기인지 확인하고 싶었기 때문이다","hints":[["준호가 어떤 점을 궁금해했는지 떠올려보자 😊"],["바로 믿기 전에 다시 생각해 본 점이 중요해!"]]},{"question_id":2,"scene_image":"scene_check_information.png","related_sentence":"준호는 정확한 설명이나 근거가 부족하다고 느꼈어요.","question":"인터넷 정보를 볼 때 근거를 확인하는 것은 왜 중요할까요?","options":["맞는 정보인지 생각해 볼 수 있어서","영상을 빨리 넘길 수 있어서","무조건 재미있어 보여서"],"answer":"맞는 정보인지 생각해 볼 수 있어서","hints":[["근거를 보면 어떤 도움이 될까? 🌱"],["정보가 맞는지 다시 생각해 보는 데 도움이 돼!"]]},{"question_id":3,"scene_image":"scene_talk_parents.png","related_sentence":"준호는 부모님과 함께 다시 찾아보기로 했어요.","question":"준호가 부모님과 함께 확인해 보려 한 것은 왜 좋은 방법일까요?","options":["함께 이야기하며 정보를 다시 살펴볼 수 있어서","더 빨리 영상을 지울 수 있어서","인터넷을 못 보게 되어서"],"answer":"함께 이야기하며 정보를 다시 살펴볼 수 있어서","hints":[["혼자 보기보다 함께 보면 어떤 점이 좋을까? 😊"],["다른 사람과 같이 확인하면 놓친 부분을 찾을 수도 있어!"]]}]},{"cycle_number":5,"cycle_type":"summary_fill","summary_template":"준호는 인터넷에서 본 영상을 보고 정말 가능한 이야기인지 궁금했어요. 영상을 끝까지 본 뒤 설명과 [BLANK_1] 부족하다고 느꼈어요. 그래서 바로 믿지 않고 [BLANK_2] 다시 찾아보기로 했어요.","questions":[{"question_id":1,"target_blank":"BLANK_1","question":"준호는 무엇이 부족하다고 느꼈나요?","options":["근거가","음악이","사람이"],"answer":"근거가","hints":[["설명과 함께 나온 중요한 낱말을 떠올려보자 🌱"],["왜 그런지 알려 주는 자료를 뭐라고 했지?"]]},{"question_id":2,"target_blank":"BLANK_2","question":"준호는 누구와 함께 다시 찾아보기로 했나요?","options":["부모님과","친구들과","혼자"],"answer":"부모님과","hints":[["준호가 함께 확인하려고 한 사람을 찾아보자 😊"],["가족과 함께 다시 찾아보기로 했어!"]]},{"question_id":3,"target_blank":null,"question":"이 글에서 알 수 있는 생각으로 알맞은 것은 무엇인가요?","options":["인터넷 정보는 한 번 더 확인하는 것이 중요하다","인터넷 영상은 모두 믿어야 한다","재미있는 제목이면 모두 사실이다"],"answer":"인터넷 정보는 한 번 더 확인하는 것이 중요하다","hints":[["준호가 마지막에 어떤 생각을 했는지 떠올려보자 🌱"],["바로 믿지 않고 다시 확인한 점이 중요해!"]]}]}]}'::jsonb)
INSERT INTO korean_step (grade, step_number, step_title, concept, content_json) VALUES
(6, 2, '우리 반 쉬는 시간 이야기', '의견 조정, 토론, 이유 말하기', '{"subject":"korean","step_id":"grade6_step2","step_title":"우리 반 쉬는 시간 이야기","grade":6,"unit_concept":["의견 조정","토론","이유 말하기"],"passage":{"title":"우리 반 쉬는 시간 이야기","text":"쉬는 시간마다 교실이 시끄러워져서 수아는 책 읽기가 힘들었어요. 반 친구들은 쉬는 시간에는 자유롭게 이야기하고 놀고 싶다고 말했어요. 선생님은 서로의 생각을 들어 보자고 했어요. 친구들은 교실 한쪽에서는 조용히 지내고, 다른 쪽에서는 이야기하기로 정했어요. 수아도 친구들도 모두 조금 더 편하게 쉬는 시간을 보낼 수 있게 되었어요.","image":"passage_grade6_step2.png"},"cycles":[{"cycle_number":1,"cycle_type":"word_card","slides":[{"word":"의견","image":"word_uigyeon.png","description":"어떤 일에 대한 내 생각이에요!","confirm_button_text":"이해했어!"},{"word":"자유롭게","image":"word_jayurobge.png","description":"마음대로 편하게 하는 모습이에요!","confirm_button_text":"이해했어!"},{"word":"정하다","image":"word_jeonghada.png","description":"어떻게 할지 함께 결정하는 것이에요!","confirm_button_text":"시작해볼게!"}]},{"cycle_number":2,"cycle_type":"fact_check","questions":[{"question_id":1,"related_sentence":"쉬는 시간마다 교실이 시끄러워져서 수아는 책 읽기가 힘들었어요.","question":"수아는 시끄러운 교실에서 책 읽기가 힘들었나요?","options":["O","X"],"answer":"O","hints":[["수아가 어떤 점을 힘들어했는지 찾아보자 😊"],["첫 문장에 중요한 답이 숨어 있어!"]]},{"question_id":2,"related_sentence":"반 친구들은 쉬는 시간에는 자유롭게 이야기하고 놀고 싶다고 말했어요.","question":"친구들은 쉬는 시간에 무엇을 하고 싶어 했나요?","options":["자유롭게 이야기하고 놀고 싶어 했다","계속 조용히 있고 싶어 했다","운동장에만 나가고 싶어 했다"],"answer":"자유롭게 이야기하고 놀고 싶어 했다","hints":[["친구들의 생각을 천천히 읽어보자 🌱"],["''이야기하고 놀고 싶다''는 표현이 보여!"]]},{"question_id":3,"related_sentence":"친구들은 교실 한쪽에서는 조용히 지내고, 다른 쪽에서는 이야기하기로 정했어요.","question":"친구들은 어떻게 하기로 정했나요?","options":["조용한 곳과 이야기하는 곳을 나누기로 했다","쉬는 시간을 없애기로 했다","아무 말도 하지 않기로 했다"],"answer":"조용한 곳과 이야기하는 곳을 나누기로 했다","hints":[["마지막 부분을 다시 읽어보자 😊"],["교실을 어떻게 사용하기로 했는지 보면 돼!"]]}]},{"cycle_number":3,"cycle_type":"diagram_order","diagram_type":"sequence","boxes":[{"id":1,"is_blank":false,"content":"수아가 시끄러운 교실 때문에 힘들어했다"},{"id":2,"is_blank":true},{"id":3,"is_blank":true},{"id":4,"is_blank":true}],"questions":[{"question_id":1,"target_box":2,"related_sentence":"반 친구들은 쉬는 시간에는 자유롭게 이야기하고 놀고 싶다고 말했어요.","question":"다른 친구들은 어떤 생각을 말했나요?","options":["자유롭게 이야기하고 놀고 싶다고 말했다","계속 공부하고 싶다고 말했다","쉬는 시간이 싫다고 말했다"],"answer":"자유롭게 이야기하고 놀고 싶다고 말했다","hints":[["친구들의 의견을 찾아보자 🌱"],["쉬는 시간에 무엇을 하고 싶어 했는지 보면 돼!"]]},{"question_id":2,"target_box":3,"related_sentence":"선생님은 서로의 생각을 들어 보자고 했어요.","question":"선생님은 친구들에게 무엇을 해 보자고 했나요?","options":["서로의 생각을 들어 보자고 했다","조용히 있으라고만 했다","쉬는 시간을 줄이자고 했다"],"answer":"서로의 생각을 들어 보자고 했다","hints":[["선생님이 한 말을 천천히 읽어보자 😊"],["''생각을 들어 보자''는 표현이 중요한 힌트야!"]]},{"question_id":3,"target_box":4,"related_sentence":"수아도 친구들도 모두 조금 더 편하게 쉬는 시간을 보낼 수 있게 되었어요.","question":"방법을 정한 뒤 어떻게 되었나요?","options":["모두 조금 더 편하게 쉬게 되었다","더 크게 싸우게 되었다","아무 변화가 없었다"],"answer":"모두 조금 더 편하게 쉬게 되었다","hints":[["마지막 문장을 다시 읽어보자 🌱"],["수아와 친구들이 어떻게 되었는지 찾아보면 돼!"]]}]},{"cycle_number":4,"cycle_type":"inference","questions":[{"question_id":1,"scene_image":"scene_noisy_class.png","related_sentence":"수아는 책 읽기가 힘들었어요.","question":"수아는 왜 힘들었을까요?","options":["조용히 책 읽기 어려웠기 때문이다","친구들이 싫었기 때문이다","쉬는 시간이 길었기 때문이다"],"answer":"조용히 책 읽기 어려웠기 때문이다","hints":[["수아가 하고 싶었던 것을 떠올려보자 😊"],["시끄러우면 책 읽기 힘들 수 있어!"]]},{"question_id":2,"scene_image":"scene_friends_talk.png","related_sentence":"반 친구들은 자유롭게 이야기하고 놀고 싶다고 말했어요.","question":"친구들에게 쉬는 시간이 중요한 이유는 무엇일까요?","options":["편하게 이야기하고 쉴 수 있어서","계속 공부할 수 있어서","혼자 있기 좋아서"],"answer":"편하게 이야기하고 쉴 수 있어서","hints":[["쉬는 시간에 친구들은 무엇을 하고 싶어 했을까? 🌱"],["쉬는 시간은 편하게 쉬는 시간이기도 해!"]]},{"question_id":3,"scene_image":"scene_class_solution.png","related_sentence":"친구들은 방법을 정했어요.","question":"서로의 의견을 듣고 방법을 정한 것은 왜 좋았을까요?","options":["모두의 생각을 함께 생각할 수 있어서","한 사람만 결정할 수 있어서","더 시끄러워질 수 있어서"],"answer":"모두의 생각을 함께 생각할 수 있어서","hints":[["여러 사람의 생각을 들으면 어떤 점이 좋을까? 😊"],["함께 방법을 찾으면 모두가 조금 더 편해질 수 있어!"]]}]},{"cycle_number":5,"cycle_type":"summary_fill","summary_template":"수아는 시끄러운 교실 때문에 책 읽기가 힘들었어요. 하지만 친구들은 자유롭게 놀고 싶어 했어요. 그래서 친구들은 서로의 의견을 듣고 [BLANK_1] 수아와 친구들은 모두 [BLANK_2] 쉬는 시간을 보내게 되었어요.","questions":[{"question_id":1,"target_blank":"BLANK_1","question":"친구들은 무엇을 했나요?","options":["방법을 정했다","계속 싸웠다","아무 말도 하지 않았다"],"answer":"방법을 정했다","hints":[["친구들이 마지막에 한 행동을 떠올려보자 🌱"],["함께 결정한 것이 있었어!"]]},{"question_id":2,"target_blank":"BLANK_2","question":"방법을 정한 뒤 어떻게 되었나요?","options":["조금 더 편하게","더 힘들게","더 시끄럽게"],"answer":"조금 더 편하게","hints":[["수아와 친구들이 어떻게 변했는지 생각해보자 😊"],["마지막 문장에 답이 숨어 있어!"]]},{"question_id":3,"target_blank":null,"question":"이 글에서 알 수 있는 생각으로 알맞은 것은 무엇인가요?","options":["의견이 다를 때는 서로 이야기하며 방법을 찾을 수 있다","내 생각만 말하는 것이 가장 중요하다","문제가 생기면 그냥 참아야 한다"],"answer":"의견이 다를 때는 서로 이야기하며 방법을 찾을 수 있다","hints":[["수아와 친구들이 어떻게 해결했는지 떠올려보자 🌱"],["서로 이야기한 점이 중요해!"]]}]}]}'::jsonb)
INSERT INTO korean_step (grade, step_number, step_title, concept, content_json) VALUES
(6, 3, '인터넷에서 본 정보가 진짜일까?', '비판적 읽기, 정보 확인, 근거 찾기', '{"subject":"korean","step_id":"grade6_step3","step_title":"인터넷에서 본 정보가 진짜일까?","grade":6,"unit_concept":["비판적 읽기","정보 확인","근거 찾기"],"passage":{"title":"인터넷에서 본 정보가 진짜일까?","text":"하린이는 인터넷에서 ''내일 학교가 쉰대!''라는 글을 보게 되었어요. 친구들은 정말 쉬는 거냐며 신나했어요. 하지만 하린이는 어디에서 나온 정보인지 먼저 확인해 보고 싶었어요. 하린이는 학교 알림장과 학교 홈페이지를 다시 살펴보았어요. 그 글은 사실이 아니었고, 친구들도 다시 정확한 정보를 확인하게 되었어요.","image":"passage_grade6_step3.png"},"cycles":[{"cycle_number":1,"cycle_type":"word_card","slides":[{"word":"정보","image":"word_information.png","description":"알려 주는 내용이나 소식이에요!","confirm_button_text":"이해했어!"},{"word":"확인","image":"word_check.png","description":"맞는지 다시 살펴보는 것이에요!","confirm_button_text":"이해했어!"},{"word":"사실","image":"word_fact.png","description":"정말로 맞는 일이에요!","confirm_button_text":"시작해볼게!"}]},{"cycle_number":2,"cycle_type":"fact_check","questions":[{"question_id":1,"related_sentence":"하린이는 인터넷에서 ''내일 학교가 쉰대!''라는 글을 보게 되었어요.","question":"하린이는 인터넷에서 학교가 쉰다는 글을 봤나요?","options":["O","X"],"answer":"O","hints":[["첫 문장을 천천히 읽어보자 😊"],["하린이가 본 글의 내용 안에 답이 있어!"]]},{"question_id":2,"related_sentence":"하린이는 어디에서 나온 정보인지 먼저 확인해 보고 싶었어요.","question":"하린이는 무엇을 먼저 확인하고 싶어 했나요?","options":["어디에서 나온 정보인지","누가 제일 먼저 봤는지","친구들이 얼마나 신났는지"],"answer":"어디에서 나온 정보인지","hints":[["하린이가 궁금해한 점을 찾아보자 🌱"],["''어디에서 나온 정보인지''라는 표현이 보여!"]]},{"question_id":3,"related_sentence":"그 글은 사실이 아니었어요.","question":"인터넷 글은 정말 사실이었나요?","options":["O","X"],"answer":"X","hints":[["마지막 부분을 다시 읽어보자 😊"],["''사실이 아니었어요''라는 표현이 힌트야!"]]}]},{"cycle_number":3,"cycle_type":"diagram_order","diagram_type":"sequence","boxes":[{"id":1,"is_blank":false,"content":"하린이가 인터넷 글을 보았다"},{"id":2,"is_blank":true},{"id":3,"is_blank":true},{"id":4,"is_blank":true}],"questions":[{"question_id":1,"target_box":2,"related_sentence":"친구들은 정말 쉬는 거냐며 신나했어요.","question":"인터넷 글을 본 친구들은 어떤 반응을 보였나요?","options":["정말 쉬는 줄 알고 신나했다","아무 관심이 없었다","바로 거짓말이라고 말했다"],"answer":"정말 쉬는 줄 알고 신나했다","hints":[["친구들의 모습을 떠올려보자 😊"],["''신나했어요''라는 표현이 보여!"]]},{"question_id":2,"target_box":3,"related_sentence":"하린이는 학교 알림장과 학교 홈페이지를 다시 살펴보았어요.","question":"하린이는 정보를 확인하기 위해 무엇을 했나요?","options":["알림장과 홈페이지를 다시 살펴보았다","인터넷 글만 계속 읽었다","친구 말만 믿었다"],"answer":"알림장과 홈페이지를 다시 살펴보았다","hints":[["하린이가 어떻게 확인했는지 찾아보자 🌱"],["학교에서 알려 주는 곳을 다시 살펴봤어!"]]},{"question_id":3,"target_box":4,"related_sentence":"친구들도 다시 정확한 정보를 확인하게 되었어요.","question":"마지막에 친구들은 어떻게 되었나요?","options":["정확한 정보를 다시 확인하게 되었다","계속 잘못 믿고 있었다","인터넷을 사용하지 않게 되었다"],"answer":"정확한 정보를 다시 확인하게 되었다","hints":[["마지막 문장을 다시 읽어보자 😊"],["친구들이 무엇을 확인하게 되었는지 보면 돼!"]]}]},{"cycle_number":4,"cycle_type":"inference","questions":[{"question_id":1,"scene_image":"scene_fake_school_post.png","related_sentence":"하린이는 어디에서 나온 정보인지 먼저 확인해 보고 싶었어요.","question":"하린이는 왜 바로 믿지 않았을까요?","options":["정확한 정보인지 알고 싶었기 때문이다","인터넷이 싫었기 때문이다","학교 가는 것이 좋았기 때문이다"],"answer":"정확한 정보인지 알고 싶었기 때문이다","hints":[["하린이가 중요하게 생각한 것을 떠올려보자 🌱"],["바로 믿기 전에 다시 확인해 본 점이 중요해!"]]},{"question_id":2,"scene_image":"scene_school_homepage.png","related_sentence":"하린이는 학교 알림장과 학교 홈페이지를 다시 살펴보았어요.","question":"학교 홈페이지를 다시 살펴본 것은 왜 좋은 방법일까요?","options":["정확한 정보를 다시 확인할 수 있어서","더 재미있는 글을 볼 수 있어서","친구들을 놀라게 할 수 있어서"],"answer":"정확한 정보를 다시 확인할 수 있어서","hints":[["정보를 다시 확인하면 어떤 점이 좋을까? 😊"],["학교에서 알려 주는 내용을 보면 도움이 될 수 있어!"]]},{"question_id":3,"scene_image":"scene_friends_check.png","related_sentence":"친구들도 다시 정확한 정보를 확인하게 되었어요.","question":"친구들이 다시 정보를 확인한 것은 왜 중요할까요?","options":["잘못된 정보를 그대로 믿지 않을 수 있어서","더 빨리 집에 갈 수 있어서","인터넷을 못 하게 되어서"],"answer":"잘못된 정보를 그대로 믿지 않을 수 있어서","hints":[["정보를 다시 확인하면 어떤 도움이 될까? 🌱"],["맞는지 살펴보면 잘못 믿는 일을 줄일 수 있어!"]]}]},{"cycle_number":5,"cycle_type":"summary_fill","summary_template":"하린이는 인터넷에서 학교가 쉰다는 글을 봤어요. 하지만 바로 믿지 않고 어디에서 나온 [BLANK_1] 먼저 확인했어요. 하린이는 학교 알림장과 홈페이지를 다시 살펴보았고, 그 글은 [BLANK_2]","questions":[{"question_id":1,"target_blank":"BLANK_1","question":"하린이는 무엇을 먼저 확인했나요?","options":["정보를","숙제를","날씨를"],"answer":"정보를","hints":[["하린이가 다시 살펴본 것을 떠올려보자 😊"],["맞는지 알아보려고 한 것이 힌트야!"]]},{"question_id":2,"target_blank":"BLANK_2","question":"인터넷 글은 결국 어떻게 밝혀졌나요?","options":["사실이 아니었다","모두 맞았다","아무도 몰랐다"],"answer":"사실이 아니었다","hints":[["마지막 부분을 다시 읽어보자 🌱"],["정말 맞는 정보였는지 떠올려보면 돼!"]]},{"question_id":3,"target_blank":null,"question":"이 글에서 알 수 있는 생각으로 알맞은 것은 무엇인가요?","options":["인터넷 정보는 다시 확인하는 것이 중요하다","인터넷 글은 모두 믿어야 한다","친구가 말하면 무조건 맞다"],"answer":"인터넷 정보는 다시 확인하는 것이 중요하다","hints":[["하린이가 마지막에 어떻게 행동했는지 떠올려보자 😊"],["바로 믿지 않고 다시 확인한 점이 중요해!"]]}]}]}'::jsonb)
